"""
Parameterized generator for GH1128_FLAML_1475.

Source PR:    https://github.com/microsoft/FLAML/pull/1475
Source Issue: https://github.com/microsoft/FLAML/issues/1318

Seed varies: renames 'about' identifier with suffix across seeds.

Bug: pre-PR state of workspace files contains the bug the PR fixes.
Fix: agent must replicate the PR's changes guided by spec.md.
"""
from __future__ import annotations

import os
from generators.base import TaskGenerator, GeneratedTask


class Generator(TaskGenerator):
    task_id = 'GH1128_FLAML_1475'
    domain = "Real-World GitHub"
    difficulty = "medium"
    languages = ["python"]

    def generate(self, seed: int) -> GeneratedTask:
        tasks_dir = os.path.join(
            os.path.dirname(__file__), "..", "tasks", 'GH1128_FLAML_1475'
        )
        with open(os.path.join(tasks_dir, "spec.md")) as f:
            spec_md = f.read()
        with open(os.path.join(tasks_dir, "brief.md")) as f:
            brief_md = f.read()

        files = self._base_workspace()
        # Apply seed-based renaming to prevent direct memorization
        suffixes = ["", "_alt", "_impl"]
        suffix = suffixes[seed % len(suffixes)]
        if suffix:
            for fpath in list(files.keys()):
                files[fpath] = files[fpath].replace('about', 'about' + suffix)
        # Deep parameterization — consistent cross-seed variation
        from generators.gh_deep_param import deep_rename_symbols, add_realistic_noise
        files = deep_rename_symbols(files, seed, strategy="mixed")
        files = add_realistic_noise(files, seed, noise_level=0.15)
        return GeneratedTask(
            task_id='GH1128_FLAML_1475',
            seed=seed,
            spec_md=spec_md,
            brief_md=brief_md,
            expected={
                "seed": seed,
                "repo": 'microsoft/FLAML',
                "pr_number": 1475,
                "bug_fixed": True,
            },
            workspace_files=files,
            metadata={
                "difficulty": "medium",
                "category": "Real-World GitHub",
                "source_pr": "https://github.com/microsoft/FLAML/pull/1475",
            },
        )

    def _base_workspace(self) -> dict[str, str]:
        """Return the pre-PR (buggy) workspace files."""
        return {
            'flaml/automl/automl.py': '# !\n#  * Copyright (c) FLAML authors. All rights reserved.\n#  * Licensed under the MIT License. See LICENSE file in the\n#  * project root for license information.\nfrom __future__ import annotations\n\nimport inspect\nimport json\nimport logging\nimport os\nimport random\nimport sys\nimport time\nfrom concurrent.futures import as_completed\nfrom functools import partial\nfrom typing import Callable, List, Optional, Union\n\nimport numpy as np\n\nfrom flaml import tune\nfrom flaml.automl.logger import logger, logger_formatter\nfrom flaml.automl.ml import huggingface_metric_to_mode, sklearn_metric_name_set, spark_metric_name_dict, train_estimator\nfrom flaml.automl.spark import DataFrame, Series, psDataFrame, psSeries\nfrom flaml.automl.state import AutoMLState, SearchState\nfrom flaml.automl.task.factory import task_factory\n\n# TODO check to see when we can remove these\nfrom flaml.automl.task.task import CLASSIFICATION, Task\nfrom flaml.automl.time_series import TimeSeriesDataset\nfrom flaml.automl.training_log import training_log_reader, training_log_writer\nfrom flaml.config import (\n    CV_HOLDOUT_THRESHOLD,\n    MEM_THRES,\n    MIN_SAMPLE_TRAIN,\n    N_SPLITS,\n    RANDOM_SEED,\n    SAMPLE_MULTIPLY_FACTOR,\n    SMALL_LARGE_THRES,\n    SPLIT_RATIO,\n)\nfrom flaml.default import suggest_learner\nfrom flaml.tune.spark.utils import check_spark, get_broadcast_data\nfrom flaml.version import __version__ as flaml_version\n\nERROR = (\n    DataFrame is None and ImportError("please install flaml[automl] option to use the flaml.automl package.") or None\n)\n\ntry:\n    from sklearn.base import BaseEstimator\n    from sklearn.pipeline import Pipeline\nexcept ImportError:\n    BaseEstimator = object\n    ERROR = ERROR or ImportError("please install flaml[automl] option to use the flaml.automl package.")\n\ntry:\n    import mlflow\nexcept ImportError:\n    mlflow = None\n\ntry:\n    from flaml.fabric.mlflow import MLflowIntegration, get_mlflow_log_latency, infer_signature, is_autolog_enabled\n\n    internal_mlflow = True\nexcept ImportError:\n    internal_mlflow = False\n\n\ntry:\n    from ray import __version__ as ray_version\n\n    assert ray_version >= "1.10.0"\n    ray_available = True\nexcept (ImportError, AssertionError):\n    ray_available = False\n\n\ndef size(learner_classes: dict, config: dict) -> float:\n    """Size function.\n\n    Returns:\n        The mem size in bytes for a config.\n    """\n    config = config.get("ml", config)\n    estimator = config["learner"]\n    learner_class = learner_classes.get(estimator)\n    return learner_class.size(config)\n\n\nclass AutoML(BaseEstimator):\n    """The AutoML class.\n    Example:\n\n    ```python\n    automl = AutoML()\n    automl_settings = {\n        "time_budget": 60,\n        "metric": \'accuracy\',\n        "task": \'classification\',\n        "log_file_name": \'mylog.log\',\n    }\n    automl.fit(X_train = X_train, y_train = y_train, **automl_settings)\n    ```\n\n    """\n\n    __version__ = flaml_version\n\n    def __init__(self, **settings):\n        """Constructor.\n\n        Many settings in fit() can be passed to the constructor too.\n        If an argument in fit() is provided, it will override the setting passed to the constructor.\n        If an argument in fit() is not provided but provided in the constructor, the value passed to the constructor will be used.\n\n        Args:\n            metric: A string of the metric name or a function,\n                e.g., \'accuracy\', \'roc_auc\', \'roc_auc_ovr\', \'roc_auc_ovo\', \'roc_auc_weighted\',\n                \'roc_auc_ovo_weighted\', \'roc_auc_ovr_weighted\', \'f1\', \'micro_f1\', \'macro_f1\',\n                \'log_loss\', \'mae\', \'mse\', \'r2\', \'mape\'. Default is \'auto\'.\n                If passing a customized metric function, the function needs to\n                have the following input arguments:\n\n        ```python\n        def custom_metric(\n            X_test, y_test, estimator, labels,\n            X_train, y_train, weight_test=None, weight_train=None,\n            config=None, groups_test=None, groups_train=None,\n        ):\n            return metric_to_minimize, metrics_to_log\n        ```\n                which returns a float number as the minimization objective,\n                and a dictionary as the metrics to log. E.g.,\n\n        ```python\n        def custom_metric(\n            X_val, y_val, estimator, labels,\n            X_train, y_train, weight_val=None, weight_train=None,\n            *args,\n        ):\n            from sklearn.metrics import log_loss\n            import time\n\n            start = time.time()\n            y_pred = estimator.predict_proba(X_val)\n            pred_time = (time.time() - start) / len(X_val)\n            val_loss = log_loss(y_val, y_pred, labels=labels, sample_weight=weight_val)\n            y_pred = estimator.predict_proba(X_train)\n            train_loss = log_loss(y_train, y_pred, labels=labels, sample_weight=weight_train)\n            alpha = 0.5\n            return val_loss * (1 + alpha) - alpha * train_loss, {\n                "val_loss": val_loss,\n                "train_loss": train_loss,\n                "pred_time": pred_time,\n            }\n        ```\n            task: A string of the task type, e.g.,\n                \'classification\', \'regression\', \'ts_forecast\', \'rank\',\n                \'seq-classification\', \'seq-regression\', \'summarization\',\n                or an instance of the Task class.\n            n_jobs: An integer of the number of threads for training | default=-1.\n                Use all available resources when n_jobs == -1.\n            log_file_name: A string of the log file name | default="". To disable logging,\n                set it to be an empty string "".\n            estimator_list: A list of strings for estimator names, or \'auto\'.\n                e.g., ```[\'lgbm\', \'xgboost\', \'xgb_limitdepth\', \'catboost\', \'rf\', \'extra_tree\']```.\n            time_budget: A float number of the time budget in seconds.\n                Use -1 if no time limit.\n            max_iter: An integer of the maximal number of iterations.\n            sample: A boolean of whether to sample the training data during\n                search.\n            ensemble: boolean or dict | default=False. Whether to perform\n                ensemble after search. Can be a dict with keys \'passthrough\'\n                and \'final_estimator\' to specify the passthrough and\n                final_estimator in the stacker. The dict can also contain\n                \'n_jobs\' as the key to specify the number of jobs for the stacker.\n            eval_method: A string of resampling strategy, one of\n                [\'auto\', \'cv\', \'holdout\'].\n            split_ratio: A float of the valiation data percentage for holdout.\n            n_splits: An integer of the number of folds for cross - validation.\n            log_type: Specifies which logs to save. One of [\'better\', \'all\']. Default is \'better\'.\n                - \'better\': Logs configs and models (if `model_history` is True) only when the loss improves,\n                  to `log_file_name` and MLflow, respectively.\n                - \'all\': Logs all configs and models (if `model_history` is True), regardless of performance.\n                Note: Configs are always logged to MLflow if MLflow logging is enabled.\n            model_history: A boolean of whether to keep the best\n                model per estimator. Make sure memory is large enough if setting to True. Default False.\n            log_training_metric: A boolean of whether to log the training\n                metric for each model.\n            mem_thres: A float of the memory size constraint in bytes.\n            pred_time_limit: A float of the prediction latency constraint in seconds.\n                It refers to the average prediction time per row in validation data.\n            train_time_limit: None or a float of the training time constraint in seconds for each trial.\n                Only valid for sequential search.\n            verbose: int, default=3 | Controls the verbosity, higher means more\n                messages.\n                verbose=0: logger level = CRITICAL\n                verbose=1: logger level = ERROR\n                verbose=2: logger level = WARNING\n                verbose=3: logger level = INFO\n                verbose=4: logger level = DEBUG\n                verbose>5: logger level = NOTSET\n            retrain_full: bool or str, default=True | whether to retrain the\n                selected model on the full training data when using holdout.\n                True - retrain only after search finishes; False - no retraining;\n                \'budget\' - do best effort to retrain without violating the time\n                budget.\n            split_type: str or splitter object, default="auto" | the data split type.\n                * A valid splitter object is an instance of a derived class of scikit-learn\n                [KFold](https://scikit-learn.org/stable/modules/generated/sklearn.model_selection.KFold.html#sklearn.model_selection.KFold)\n                and have ``split`` and ``get_n_splits`` methods with the same signatures.\n                Set eval_method to "cv" to use the splitter object.\n                * Valid str options depend on different tasks.\n                For classification tasks, valid choices are\n                    ["auto", \'stratified\', \'uniform\', \'time\', \'group\']. "auto" -> stratified.\n                For regression tasks, valid choices are ["auto", \'uniform\', \'time\', \'group\'].\n                    "auto" -> uniform.\n                For time series forecast tasks, must be "auto" or \'time\'.\n                For ranking task, must be "auto" or \'group\'.\n            hpo_method: str, default="auto" | The hyperparameter\n                optimization method. By default, CFO is used for sequential\n                search and BlendSearch is used for parallel search.\n                No need to set when using flaml\'s default search space or using\n                a simple customized search space. When set to \'bs\', BlendSearch\n                is used. BlendSearch can be tried when the search space is\n                complex, for example, containing multiple disjoint, discontinuous\n                subspaces. When set to \'random\', random search is used.\n            starting_points: A dictionary or a str to specify the starting hyperparameter\n                config for the estimators | default="static".\n                If str:\n                    - if "data", use data-dependent defaults;\n                    - if "data:path" use data-dependent defaults which are stored at path;\n                    - if "static", use data-independent defaults.\n                If dict, keys are the name of the estimators, and values are the starting\n                hyperparameter configurations for the corresponding estimators.\n                The value can be a single hyperparameter configuration dict or a list\n                of hyperparameter configuration dicts.\n                In the following code example, we get starting_points from the\n                `automl` object and use them in the `new_automl` object.\n                e.g.,\n\n        ```python\n        from flaml import AutoML\n        automl = AutoML()\n        X_train, y_train = load_iris(return_X_y=True)\n        automl.fit(X_train, y_train)\n        starting_points = automl.best_config_per_estimator\n\n        new_automl = AutoML()\n        new_automl.fit(X_train, y_train, starting_points=starting_points)\n        ```\n\n            seed: int or None, default=None | The random seed for hpo.\n            n_concurrent_trials: [In preview] int, default=1 | The number of\n                concurrent trials. When n_concurrent_trials > 1, flaml performes\n                [parallel tuning](/docs/Use-Cases/Task-Oriented-AutoML#parallel-tuning)\n                and installation of ray or spark is required: `pip install flaml[ray]`\n                or `pip install flaml[spark]`. Please check\n                [here](https://spark.apache.org/docs/latest/api/python/getting_started/install.html)\n                for more details about installing Spark.\n            keep_search_state: boolean, default=False | Whether to keep data needed\n                for model search after fit(). By default the state is deleted for\n                space saving.\n            preserve_checkpoint: boolean, default=True | Whether to preserve the saved checkpoint\n                on disk when deleting automl. By default the checkpoint is preserved.\n            early_stop: boolean, default=False | Whether to stop early if the\n                search is considered to converge.\n            force_cancel: boolean, default=False | Whether to forcely cancel Spark jobs if the\n                search time exceeded the time budget.\n            mlflow_exp_name: str, default=None | The name of the mlflow experiment. This should be specified if\n                enable mlflow autologging on Spark. Otherwise it will log all the results into the experiment of the\n                same name as the basename of main entry file.\n            append_log: boolean, default=False | Whetehr to directly append the log\n                records to the input log file if it exists.\n            auto_augment: boolean, default=True | Whether to automatically\n                augment rare classes.\n            min_sample_size: int, default=MIN_SAMPLE_TRAIN | the minimal sample\n                size when sample=True.\n            use_ray: boolean or dict.\n                If boolean: default=False | Whether to use ray to run the training\n                in separate processes. This can be used to prevent OOM for large\n                datasets, but will incur more overhead in time.\n                If dict: the dict contains the keywords arguments to be passed to\n                [ray.tune.run](https://docs.ray.io/en/latest/tune/api_docs/execution.html).\n            use_spark: boolean, default=False | Whether to use spark to run the training\n                in parallel spark jobs. This can be used to accelerate training on large models\n                and large datasets, but will incur more overhead in time and thus slow down\n                training in some cases. GPU training is not supported yet when use_spark is True.\n                For Spark clusters, by default, we will launch one trial per executor. However,\n                sometimes we want to launch more trials than the number of executors (e.g., local mode).\n                In this case, we can set the environment variable `FLAML_MAX_CONCURRENT` to override\n                the detected `num_executors`. The final number of concurrent trials will be the minimum\n                of `n_concurrent_trials` and `num_executors`.\n            free_mem_ratio: float between 0 and 1, default=0. The free memory ratio to keep during training.\n            metric_constraints: list, default=[] | The list of metric constraints.\n                Each element in this list is a 3-tuple, which shall be expressed\n                in the following format: the first element of the 3-tuple is the name of the\n                metric, the second element is the inequality sign chosen from ">=" and "<=",\n                and the third element is the constraint value. E.g., `(\'val_loss\', \'<=\', 0.1)`.\n                Note that all the metric names in metric_constraints need to be reported via\n                the metrics_to_log dictionary returned by a customized metric function.\n                The customized metric function shall be provided via the `metric` key word\n                argument of the fit() function or the automl constructor.\n                Find an example in the 4th constraint type in this [doc](/docs/Use-Cases/Task-Oriented-AutoML#constraint).\n                If `pred_time_limit` is provided as one of keyword arguments to fit() function or\n                the automl constructor, flaml will automatically (and under the hood)\n                add it as an additional element in the metric_constraints. Essentially \'pred_time_limit\'\n                specifies a constraint about the prediction latency constraint in seconds.\n            custom_hp: dict, default=None | The custom search space specified by user.\n                It is a nested dict with keys being the estimator names, and values being dicts\n                per estimator search space. In the per estimator search space dict,\n                the keys are the hyperparameter names, and values are dicts of info ("domain",\n                "init_value", and "low_cost_init_value") about the search space associated with\n                the hyperparameter (i.e., per hyperparameter search space dict). When custom_hp\n                is provided, the built-in search space which is also a nested dict of per estimator\n                search space dict, will be updated with custom_hp. Note that during this nested dict update,\n                the per hyperparameter search space dicts will be replaced (instead of updated) by the ones\n                provided in custom_hp. Note that the value for "domain" can either be a constant\n                or a sample.Domain object.\n                e.g.,\n\n        ```python\n        custom_hp = {\n             "transformer_ms": {\n                 "model_path": {\n                     "domain": "albert-base-v2",\n                 },\n                 "learning_rate": {\n                     "domain": tune.choice([1e-4, 1e-5]),\n                 }\n             }\n         }\n        ```\n            skip_transform: boolean, default=False | Whether to pre-process data prior to modeling.\n            fit_kwargs_by_estimator: dict, default=None | The user specified keywords arguments, grouped by estimator name.\n                e.g.,\n\n        ```python\n        fit_kwargs_by_estimator = {\n            "transformer": {\n                "output_dir": "test/data/output/",\n                "fp16": False,\n            }\n        }\n        ```\n            mlflow_logging: boolean, default=True | Whether to log the training results to mlflow. Not valid if mlflow is not installed.\n\n        """\n        if ERROR:\n            raise ERROR\n        self._track_iter = 0\n        self._state = AutoMLState()\n        self._state.learner_classes = {}\n        self._settings = settings\n        self._automl_user_configurations = settings.copy()\n        self._settings.pop("automl_user_configurations", None)\n        # no budget by default\n        settings["time_budget"] = settings.get("time_budget", -1)\n        settings["task"] = settings.get("task", "classification")\n        settings["n_jobs"] = settings.get("n_jobs", -1)\n        settings["eval_method"] = settings.get("eval_method", "auto")\n        settings["split_ratio"] = settings.get("split_ratio", SPLIT_RATIO)\n        settings["n_splits"] = settings.get("n_splits", N_SPLITS)\n        settings["auto_augment"] = settings.get("auto_augment", True)\n        settings["metric"] = settings.get("metric", "auto")\n        settings["estimator_list"] = settings.get("estimator_list", "auto")\n        settings["log_file_name"] = settings.get("log_file_name", "")\n        settings["max_iter"] = settings.get("max_iter")  # no budget by default\n        settings["sample"] = settings.get("sample", True)\n        settings["ensemble"] = settings.get("ensemble", False)\n        settings["log_type"] = settings.get("log_type", "better")\n        settings["model_history"] = settings.get("model_history", False)\n        settings["log_training_metric"] = settings.get("log_training_metric", False)\n        settings["mem_thres"] = settings.get("mem_thres", MEM_THRES)\n        settings["pred_time_limit"] = settings.get("pred_time_limit", np.inf)\n        settings["train_time_limit"] = settings.get("train_time_limit", None)\n        settings["verbose"] = settings.get("verbose", 3)\n        settings["retrain_full"] = settings.get("retrain_full", True)\n        settings["split_type"] = settings.get("split_type", "auto")\n        settings["hpo_method"] = settings.get("hpo_method", "auto")\n        settings["learner_selector"] = settings.get("learner_selector", "sample")\n        settings["starting_points"] = settings.get("starting_points", "static")\n        settings["n_concurrent_trials"] = settings.get("n_concurrent_trials", 1)\n        settings["keep_search_state"] = settings.get("keep_search_state", False)\n        settings["preserve_checkpoint"] = settings.get("preserve_checkpoint", True)\n        settings["early_stop"] = settings.get("early_stop", False)\n        settings["force_cancel"] = settings.get("force_cancel", False)\n        settings["mlflow_exp_name"] = settings.get("mlflow_exp_name", None)\n        settings["append_log"] = settings.get("append_log", False)\n        settings["min_sample_size"] = settings.get("min_sample_size", MIN_SAMPLE_TRAIN)\n        settings["use_ray"] = settings.get("use_ray", False)\n        settings["use_spark"] = settings.get("use_spark", False)\n        if settings["use_ray"] is not False and settings["use_spark"] is not False:\n            raise ValueError("use_ray and use_spark cannot be both True.")\n        settings["free_mem_ratio"] = settings.get("free_mem_ratio", 0)\n        settings["metric_constraints"] = settings.get("metric_constraints", [])\n        settings["cv_score_agg_func"] = settings.get("cv_score_agg_func", None)\n        settings["fit_kwargs_by_estimator"] = settings.get("fit_kwargs_by_estimator", {})\n        settings["custom_hp"] = settings.get("custom_hp", {})\n        settings["skip_transform"] = settings.get("skip_transform", False)\n        settings["mlflow_logging"] = settings.get("mlflow_logging", True)\n\n        self._estimator_type = "classifier" if settings["task"] in CLASSIFICATION else "regressor"\n        self.best_run_id = None\n\n    def __getstate__(self):\n        """Customize pickling to avoid serializing runtime-only objects.\n\n        MLflow\'s sklearn flavor serializes estimators via (cloud)pickle. During\n        AutoML fitting we may attach an internal mlflow integration instance\n        which holds `concurrent.futures.Future` objects and executors containing\n        thread locks, which are not picklable.\n        """\n\n        state = self.__dict__.copy()\n        # Keep mlflow_integration for post-load visualization (e.g., infos), but\n        # strip non-picklable runtime-only members (thread futures, clients).\n        mlflow_integration = state.get("mlflow_integration", None)\n        if mlflow_integration is not None:\n            import copy\n\n            mi = copy.copy(mlflow_integration)\n            # These are runtime-only and often contain locks / threads.\n            if hasattr(mi, "futures"):\n                mi.futures = {}\n            if hasattr(mi, "futures_log_model"):\n                mi.futures_log_model = {}\n            if hasattr(mi, "train_func"):\n                mi.train_func = None\n            if hasattr(mi, "mlflow_client"):\n                mi.mlflow_client = None\n            state["mlflow_integration"] = mi\n        # MLflow signature objects may hold references to Spark/pandas-on-Spark\n        # inputs and can indirectly capture SparkContext, which is not picklable.\n        state.pop("estimator_signature", None)\n        state.pop("pipeline_signature", None)\n        return state\n\n    def __setstate__(self, state):\n        self.__dict__.update(state)\n        # Ensure mlflow_integration runtime members exist post-unpickle.\n        mi = getattr(self, "mlflow_integration", None)\n        if mi is not None:\n            if not hasattr(mi, "futures") or mi.futures is None:\n                mi.futures = {}\n            if not hasattr(mi, "futures_log_model") or mi.futures_log_model is None:\n                mi.futures_log_model = {}\n            if not hasattr(mi, "train_func"):\n                mi.train_func = None\n            if not hasattr(mi, "mlflow_client") or mi.mlflow_client is None:\n                try:\n                    import mlflow as _mlflow\n\n                    mi.mlflow_client = _mlflow.tracking.MlflowClient()\n                except Exception:\n                    mi.mlflow_client = None\n\n    def get_params(self, deep: bool = False) -> dict:\n        return self._settings.copy()\n\n    @property\n    def config_history(self) -> dict:\n        """A dictionary of iter->(estimator, config, time),\n        storing the best estimator, config, and the time when the best\n        model is updated each time.\n        """\n        return self._config_history\n\n    @property\n    def model(self):\n        """An object with `predict()` and `predict_proba()` method (for\n        classification), storing the best trained model.\n        """\n        return self.__dict__.get("_trained_estimator")\n\n    def best_model_for_estimator(self, estimator_name: str):\n        """Return the best model found for a particular estimator.\n\n        Args:\n            estimator_name: a str of the estimator\'s name.\n\n        Returns:\n            An object storing the best model for estimator_name.\n            If `model_history` was set to False during fit(), then the returned model\n            is untrained unless estimator_name is the best estimator.\n            If `model_history` was set to True, then the returned model is trained.\n        """\n        state = self._search_states.get(estimator_name)\n        if state and estimator_name == self._best_estimator:\n            return self.model\n        return state and getattr(state, "trained_estimator", None)\n\n    @property\n    def best_estimator(self):\n        """A string indicating the best estimator found."""\n        return self._best_estimator\n\n    @property\n    def best_iteration(self):\n        """An integer of the iteration number where the best\n        config is found."""\n        return self._best_iteration\n\n    @property\n    def best_config(self):\n        """A dictionary of the best configuration."""\n        state = self._search_states.get(self._best_estimator)\n        config = state and getattr(state, "best_config", None)\n        return config and AutoMLState.sanitize(config)\n\n    @property\n    def best_config_per_estimator(self):\n        """A dictionary of all estimators\' best configuration."""\n        return {\n            e: e_search_state.best_config and AutoMLState.sanitize(e_search_state.best_config)\n            for e, e_search_state in self._search_states.items()\n        }\n\n    @property\n    def best_loss_per_estimator(self):\n        """A dictionary of all estimators\' best loss."""\n        return {e: e_search_state.best_loss for e, e_search_state in self._search_states.items()}\n\n    @property\n    def best_loss(self):\n        """A float of the best loss found."""\n        return self._state.best_loss\n\n    @property\n    def best_result(self):\n        """Result dictionary for model trained with the best config."""\n        state = self._search_states.get(self._best_estimator)\n        return state and getattr(state, "best_result", None)\n\n    @property\n    def metrics_for_best_config(self):\n        """Returns a float of the best loss, and a dictionary of the auxiliary metrics to log\n        associated with the best config. These two objects correspond to the returned\n        objects by the customized metric function for the config with the best loss."""\n        state = self._search_states.get(self._best_estimator)\n        return self._state.best_loss, state and getattr(state, "best_result", {}).get("metric_for_logging")\n\n    @property\n    def best_config_train_time(self):\n        """A float of the seconds taken by training the best config."""\n        return getattr(self._search_states[self._best_estimator], "best_config_train_time", None)\n\n    def save_best_config(self, filename):\n        best = {\n            "class": self.best_estimator,\n            "hyperparameters": self.best_config,\n        }\n        os.makedirs(os.path.dirname(filename), exist_ok=True)\n        with open(filename, "w") as f:\n            json.dump(best, f)\n\n    @property\n    def supported_metrics(self):\n        """\n        Returns a tuple of supported metrics for the task.\n\n            Returns:\n                    metrics (Tuple): sklearn metrics from sklearn package;\n                                    huggingface metrics from datasets package;\n                                    spark metrics from pyspark package\n\n        """\n\n        return sklearn_metric_name_set, huggingface_metric_to_mode.keys(), spark_metric_name_dict\n\n    @property\n    def feature_transformer(self):\n        """Returns AutoML Transformer"""\n        data_precessor = getattr(self, "_transformer", None)\n        return data_precessor\n\n    @property\n    def label_transformer(self):\n        """Returns AutoML label transformer"""\n        return getattr(self, "_label_transformer", None)\n\n    @property\n    def classes_(self):\n        """A numpy array of shape (n_classes,) for class labels."""\n        attr = getattr(self, "_label_transformer", None)\n        if attr:\n            return attr.classes_\n        attr = getattr(self, "_trained_estimator", None)\n        if attr:\n            return attr.classes_\n        return None\n\n    @property\n    def n_features_in_(self):\n        return self._trained_estimator.n_features_in_\n\n    @property\n    def feature_names_in_(self):\n        attr = getattr(self, "_trained_estimator", None)\n        attr = attr and getattr(attr, "feature_names_in_", None)\n        if attr is not None:\n            return attr\n        return getattr(self, "_feature_names_in_", None)\n\n    @property\n    def feature_importances_(self):\n        attr = getattr(self, "_trained_estimator", None)\n        attr = attr and getattr(attr, "feature_importances_", None)\n        return attr\n\n    @property\n    def time_to_find_best_model(self) -> float:\n        """Time taken to find best model in seconds."""\n        return self.__dict__.get("_time_taken_best_iter")\n\n    def score(\n        self,\n        X: DataFrame | psDataFrame,\n        y: Series | psSeries,\n        **kwargs,\n    ):\n        estimator = getattr(self, "_trained_estimator", None)\n        if estimator is None:\n            logger.warning("No estimator is trained. Please run fit with enough budget.")\n            return None\n        X = self._state.task.preprocess(X, self._transformer)\n        if self._label_transformer:\n            y = self._label_transformer.transform(y)\n        return estimator.score(X, y, **kwargs)\n\n    def predict(\n        self,\n        X: np.array | DataFrame | list[str] | list[list[str]] | psDataFrame,\n        **pred_kwargs,\n    ):\n        """Predict label from features.\n\n        Args:\n            X: A numpy array or pandas dataframe or pyspark.pandas dataframe\n            of featurized instances, shape n * m,\n                or for time series forcast tasks:\n                    a pandas dataframe with the first column containing\n                    timestamp values (datetime type) or an integer n for\n                    the predict steps (only valid when the estimator is\n                    arima or sarimax). Other columns in the dataframe\n                    are assumed to be exogenous variables (categorical\n                    or numeric).\n            **pred_kwargs: Other key word arguments to pass to predict() function of\n                the searched learners, such as per_device_eval_batch_size.\n\n        ```python\n        multivariate_X_test = DataFrame({\n            \'timeStamp\': pd.date_range(start=\'1/1/2022\', end=\'1/07/2022\'),\n            \'categorical_col\': [\'yes\', \'yes\', \'no\', \'no\', \'yes\', \'no\', \'yes\'],\n            \'continuous_col\': [105, 107, 120, 118, 110, 112, 115]\n        })\n        model.predict(multivariate_X_test)\n        ```\n\n        Returns:\n            A array-like of shape n * 1: each element is a predicted\n            label for an instance.\n        """\n        estimator = getattr(self, "_trained_estimator", None)\n        if estimator is None:\n            logger.warning("No estimator is trained. Please run fit with enough budget.")\n            return None\n        X = self._state.task.preprocess(X, self._transformer)\n        y_pred = estimator.predict(X, **pred_kwargs)\n\n        if isinstance(y_pred, np.ndarray) and y_pred.ndim > 1 and isinstance(y_pred, np.ndarray):\n            y_pred = y_pred.flatten()\n        if self._label_transformer:\n            return self._label_transformer.inverse_transform(Series(y_pred.astype(int)))\n        else:\n            return y_pred\n\n    def predict_proba(self, X, **pred_kwargs):\n        """Predict the probability of each class from features, only works for\n        classification problems.\n\n        Args:\n            X: A numpy array of featurized instances, shape n * m.\n            **pred_kwargs: Other key word arguments to pass to predict_proba() function of\n                the searched learners, such as per_device_eval_batch_size.\n\n        Returns:\n            A numpy array of shape n * c. c is the  # classes. Each element at\n            (i, j) is the probability for instance i to be in class j.\n        """\n        estimator = getattr(self, "_trained_estimator", None)\n        if estimator is None:\n            logger.warning("No estimator is trained. Please run fit with enough budget.")\n            return None\n        X = self._state.task.preprocess(X, self._transformer)\n        proba = self._trained_estimator.predict_proba(X, **pred_kwargs)\n        return proba\n\n    def add_learner(self, learner_name, learner_class):\n        """Add a customized learner.\n\n        Args:\n            learner_name: A string of the learner\'s name.\n            learner_class: A subclass of flaml.automl.model.BaseEstimator.\n        """\n        self._state.learner_classes[learner_name] = learner_class\n\n    def get_estimator_from_log(self, log_file_name: str, record_id: int, task: str | Task):\n        """Get the estimator from log file.\n\n        Args:\n            log_file_name: A string of the log file name.\n            record_id: An integer of the record ID in the file,\n                0 corresponds to the first trial.\n            task: A string of the task type,\n                \'binary\', \'multiclass\', \'regression\', \'ts_forecast\', \'rank\',\n                or an instance of the Task class.\n\n        Returns:\n            An estimator object for the given configuration.\n        """\n\n        with training_log_reader(log_file_name) as reader:\n            record = reader.get_record(record_id)\n            estimator = record.learner\n            config = AutoMLState.sanitize(record.config)\n\n        if isinstance(task, str):\n            task = task_factory(task)\n\n        estimator, _ = train_estimator(\n            X_train=None,\n            y_train=None,\n            config_dic=config,\n            task=task,\n            estimator_name=estimator,\n            estimator_class=self._state.learner_classes.get(estimator),\n            eval_metric="train_time",\n        )\n        return estimator\n\n    def retrain_from_log(\n        self,\n        log_file_name,\n        X_train=None,\n        y_train=None,\n        dataframe=None,\n        label=None,\n        time_budget=np.inf,\n        task: str | Task | None = None,\n        eval_method=None,\n        split_ratio=None,\n        n_splits=None,\n        split_type=None,\n        groups=None,\n        n_jobs=-1,\n        # gpu_per_trial=0,\n        train_best=True,\n        train_full=False,\n        record_id=-1,\n        auto_augment=None,\n        custom_hp=None,\n        skip_transform=None,\n        preserve_checkpoint=True,\n        fit_kwargs_by_estimator=None,\n        **fit_kwargs,\n    ):\n        """Retrain from log file.\n\n        This function is intended to retrain the logged configurations.\n        NOTE: In some rare case, the last config is early stopped to meet time_budget and it\'s the best config.\n        But the logged config\'s ITER_HP (e.g., n_estimators) is not reduced.\n\n        Args:\n            log_file_name: A string of the log file name.\n            X_train: A numpy array or dataframe of training data in shape n*m.\n                For time series forecast tasks, the first column of X_train must be the timestamp column (datetime type). Other columns in the dataframe are assumed to be exogenous variables (categorical or numeric).\n            y_train: A numpy array or series of labels in shape n*1.\n            dataframe: A dataframe of training data including label column.\n                For time series forecast tasks, dataframe must be specified and should\n                have at least two columns: timestamp and label, where the first\n                column is the timestamp column (datetime type). Other columns\n                in the dataframe are assumed to be exogenous variables\n                (categorical or numeric).\n            label: A str of the label column name, e.g., \'label\';\n                Note: If X_train and y_train are provided,\n                dataframe and label are ignored;\n                If not, dataframe and label must be provided.\n            time_budget: A float number of the time budget in seconds.\n            task: A string of the task type, e.g.,\n                \'classification\', \'regression\', \'ts_forecast\', \'rank\',\n                \'seq-classification\', \'seq-regression\', \'summarization\',\n                or an instance of Task class.\n            eval_method: A string of resampling strategy, one of\n                [\'auto\', \'cv\', \'holdout\'].\n            split_ratio: A float of the validation data percentage for holdout.\n            n_splits: An integer of the number of folds for cross-validation.\n            split_type: str or splitter object, default="auto" | the data split type.\n                * A valid splitter object is an instance of a derived class of scikit-learn\n                [KFold](https://scikit-learn.org/stable/modules/generated/sklearn.model_selection.KFold.html#sklearn.model_selection.KFold)\n                and have ``split`` and ``get_n_splits`` methods with the same signatures.\n                Set eval_method to "cv" to use the splitter object.\n                * Valid str options depend on different tasks.\n                For classification tasks, valid choices are\n                    ["auto", \'stratified\', \'uniform\', \'time\', \'group\']. "auto" -> stratified.\n                For regression tasks, valid choices are ["auto", \'uniform\', \'time\', \'group\'].\n                    "auto" -> uniform.\n                For time series forecast tasks, must be "auto" or \'time\'.\n                For ranking task, must be "auto" or \'group\'.\n            groups: None or array-like | Group labels (with matching length to\n                y_train) or groups counts (with sum equal to length of y_train)\n                for training data.\n            n_jobs: An integer of the number of threads for training | default=-1.\n                Use all available resources when n_jobs == -1.\n            train_best: A boolean of whether to train the best config in the\n                time budget; if false, train the last config in the budget.\n            train_full: A boolean of whether to train on the full data. If true,\n                eval_method and sample_size in the log file will be ignored.\n            record_id: the ID of the training log record from which the model will\n                be retrained. By default `record_id = -1` which means this will be\n                ignored. `record_id = 0` corresponds to the first trial, and\n                when `record_id >= 0`, `time_budget` will be ignored.\n            auto_augment: boolean, default=True | Whether to automatically\n                augment rare classes.\n            custom_hp: dict, default=None | The custom search space specified by user\n                Each key is the estimator name, each value is a dict of the custom search space for that estimator. Notice the\n                domain of the custom search space can either be a value or a sample.Domain object.\n\n        ```python\n        custom_hp = {\n            "transformer_ms": {\n                "model_path": {\n                    "domain": "albert-base-v2",\n                },\n                "learning_rate": {\n                    "domain": tune.choice([1e-4, 1e-5]),\n                }\n            }\n        }\n        ```\n            fit_kwargs_by_estimator: dict, default=None | The user specified keywords arguments, grouped by estimator name.\n                e.g.,\n\n        ```python\n        fit_kwargs_by_estimator = {\n            "transformer": {\n                "output_dir": "test/data/output/",\n                "fp16": False,\n            }\n        }\n        ```\n\n            **fit_kwargs: Other key word arguments to pass to fit() function of\n                the searched learners, such as sample_weight. Below are a few examples of\n                estimator-specific parameters:\n                    period: int | forecast horizon for all time series forecast tasks.\n                    gpu_per_trial: float, default = 0 | A float of the number of gpus per trial,\n                        only used by TransformersEstimator, XGBoostSklearnEstimator, and\n                        TemporalFusionTransformerEstimator.\n                    group_ids: list of strings of column names identifying a time series, only\n                        used by TemporalFusionTransformerEstimator, required for\n                        \'ts_forecast_panel\' task. `group_ids` is a parameter for TimeSeriesDataSet object\n                        from PyTorchForecasting.\n                        For other parameters to describe your dataset, refer to\n                        [TimeSeriesDataSet PyTorchForecasting](https://pytorch-forecasting.readthedocs.io/en/stable/api/pytorch_forecasting.data.timeseries.TimeSeriesDataSet.html).\n                        To specify your variables, use `static_categoricals`, `static_reals`,\n                        `time_varying_known_categoricals`, `time_varying_known_reals`,\n                        `time_varying_unknown_categoricals`, `time_varying_unknown_reals`,\n                        `variable_groups`. To provide more information on your data, use\n                        `max_encoder_length`, `min_encoder_length`, `lags`.\n                    log_dir: str, default = "lightning_logs" | Folder into which to log results\n                        for tensorboard, only used by TemporalFusionTransformerEstimator.\n                    max_epochs: int, default = 20 | Maximum number of epochs to run training,\n                        only used by TemporalFusionTransformerEstimator.\n                    batch_size: int, default = 64 | Batch size for training model, only\n                        used by TemporalFusionTransformerEstimator and TCNEstimator.\n        """\n        task = task or self._settings.get("task")\n        if isinstance(task, str):\n            task = task_factory(task)\n\n        eval_method = eval_method or self._settings.get("eval_method")\n        split_ratio = split_ratio or self._settings.get("split_ratio")\n        n_splits = n_splits or self._settings.get("n_splits")\n        split_type = split_type or self._settings.get("split_type")\n        auto_augment = self._settings.get("auto_augment") if auto_augment is None else auto_augment\n        self._state.task = task\n        self._estimator_type = "classifier" if task.is_classification() else "regressor"\n\n        self._state.fit_kwargs = fit_kwargs\n        self._state.custom_hp = custom_hp or self._settings.get("custom_hp")\n        self._skip_transform = self._settings.get("skip_transform") if skip_transform is None else skip_transform\n        self._state.fit_kwargs_by_estimator = fit_kwargs_by_estimator or self._settings.get("fit_kwargs_by_estimator")\n        self.preserve_checkpoint = (\n            self._settings.get("preserve_checkpoint") if preserve_checkpoint is None else preserve_checkpoint\n        )\n        task.validate_data(self, self._state, X_train, y_train, dataframe, label, groups=groups)\n\n        logger.info(f"log file name {log_file_name}")\n\n        best_config = None\n        best_val_loss = float("+inf")\n        best_estimator = None\n        sample_size = None\n        time_used = 0.0\n        training_duration = 0\n        best = None\n        with training_log_reader(log_file_name) as reader:\n            if record_id >= 0:\n                best = reader.get_record(record_id)\n            else:\n                for record in reader.records():\n                    time_used = record.wall_clock_time\n                    if time_used > time_budget:\n                        break\n                    training_duration = time_used\n                    val_loss = record.validation_loss\n                    if val_loss <= best_val_loss or not train_best:\n                        if val_loss == best_val_loss and train_best:\n                            size = record.sample_size\n                            if size > sample_size:\n                                best = record\n                                best_val_loss = val_loss\n                                sample_size = size\n                        else:\n                            best = record\n                            size = record.sample_size\n                            best_val_loss = val_loss\n                            sample_size = size\n                if not training_duration:\n                    logger.warning(f"No estimator found within time_budget={time_budget}")\n                    from .model import BaseEstimator as Estimator\n\n                    self._trained_estimator = Estimator()\n                    return training_duration\n        if not best:\n            return\n        best_estimator = best.learner\n        best_config = best.config\n        sample_size = len(self._y_train_all) if train_full else best.sample_size\n\n        this_estimator_kwargs = self._state.fit_kwargs_by_estimator.get(best_estimator)\n        if this_estimator_kwargs:\n            this_estimator_kwargs = (\n                this_estimator_kwargs.copy()\n            )  # make another shallow copy of the value (a dict obj), so user\'s fit_kwargs_by_estimator won\'t be updated\n            this_estimator_kwargs.update(self._state.fit_kwargs)\n            self._state.fit_kwargs_by_estimator[best_estimator] = this_estimator_kwargs\n        else:\n            self._state.fit_kwargs_by_estimator[best_estimator] = self._state.fit_kwargs\n\n        logger.info(f"estimator = {best_estimator}, config = {best_config}, #training instances = {sample_size}")\n        # Partially copied from fit() function\n        # Initilize some attributes required for retrain_from_log\n        self._split_type = task.decide_split_type(\n            split_type,\n            self._y_train_all,\n            self._state.fit_kwargs,\n            self._state.groups,\n        )\n        eval_method = self._decide_eval_method(eval_method, time_budget)\n        self.modelcount = 0\n        self._auto_augment = auto_augment\n        self._prepare_data(eval_method, split_ratio, n_splits)\n        self._state.time_budget = -1\n        self._state.free_mem_ratio = 0\n        self._state.n_jobs = n_jobs\n        import os\n\n        self._state.resources_per_trial = (\n            {\n                "cpu": max(1, os.cpu_count() >> 1),\n                "gpu": fit_kwargs.get("gpu_per_trial", 0),\n            }\n            if self._state.n_jobs < 0\n            else {"cpu": self._state.n_jobs, "gpu": fit_kwargs.get("gpu_per_trial", 0)}\n        )\n        self._trained_estimator = self._state._train_with_config(\n            best_estimator,\n            best_config,\n            sample_size=sample_size,\n        )[0]\n        logger.info("retrain from log succeeded")\n        return training_duration\n\n    def _decide_eval_method(self, eval_method, time_budget):\n        if not isinstance(self._split_type, str):\n            assert eval_method in [\n                "auto",\n                "cv",\n            ], "eval_method must be \'auto\' or \'cv\' for custom data splitter."\n            assert self._state.X_val is None, "custom splitter and custom validation data can\'t be used together."\n            return "cv"\n        if self._state.X_val is not None and (\n            not isinstance(self._state.X_val, TimeSeriesDataset) or len(self._state.X_val.test_data) > 0\n        ):\n            assert eval_method in [\n                "auto",\n                "holdout",\n            ], "eval_method must be \'auto\' or \'holdout\' for custom validation data."\n            return "holdout"\n        if eval_method != "auto":\n            assert eval_method in [\n                "holdout",\n                "cv",\n            ], "eval_method must be \'holdout\', \'cv\' or \'auto\'."\n            return eval_method\n        nrow, dim = self._nrow, self._ndim\n        if (\n            time_budget < 0\n            or nrow * dim / 0.9 < SMALL_LARGE_THRES * (time_budget / 3600)\n            and nrow < CV_HOLDOUT_THRESHOLD\n        ):\n            # time allows or sampling can be used and cv is necessary\n            return "cv"\n        else:\n            return "holdout"\n\n    @property\n    def search_space(self) -> dict:\n        """Search space.\n\n        Must be called after fit(...)\n        (use max_iter=0 and retrain_final=False to prevent actual fitting).\n\n        Returns:\n            A dict of the search space.\n        """\n        estimator_list = self.estimator_list\n        if len(estimator_list) == 1:\n            estimator = estimator_list[0]\n            space = self._search_states[estimator].search_space.copy()\n            space["learner"] = estimator\n            return space\n        choices = []\n        for estimator in estimator_list:\n            space = self._search_states[estimator].search_space.copy()\n            space["learner"] = estimator\n            choices.append(space)\n        return {"ml": tune.choice(choices)}\n\n    @property\n    def low_cost_partial_config(self) -> dict:\n        """Low cost partial config.\n\n        Returns:\n            A dict.\n            (a) if there is only one estimator in estimator_list, each key is a\n            hyperparameter name.\n            (b) otherwise, it is a nested dict with \'ml\' as the key, and\n            a list of the low_cost_partial_configs as the value, corresponding\n            to each learner\'s low_cost_partial_config; the estimator index as\n            an integer corresponding to the cheapest learner is appended to the\n            list at the end.\n        """\n        if len(self.estimator_list) == 1:\n            estimator = self.estimator_list[0]\n            c = self._search_states[estimator].low_cost_partial_config\n            return c\n        else:\n            configs = []\n            for estimator in self.estimator_list:\n                c = self._search_states[estimator].low_cost_partial_config\n                configs.append(c)\n            configs.append(\n                np.argmin(\n                    [\n                        self._state.learner_classes.get(estimator).cost_relative2lgbm()\n                        for estimator in self.estimator_list\n                    ]\n                )\n            )\n            config = {"ml": configs}\n        return config\n\n    @property\n    def cat_hp_cost(self) -> dict:\n        """Categorical hyperparameter cost\n\n        Returns:\n            A dict.\n            (a) if there is only one estimator in estimator_list, each key is a\n            hyperparameter name.\n            (b) otherwise, it is a nested dict with \'ml\' as the key, and\n            a list of the cat_hp_cost\'s as the value, corresponding\n            to each learner\'s cat_hp_cost; the cost relative to lgbm for each\n            learner (as a list itself) is appended to the list at the end.\n        """\n        if len(self.estimator_list) == 1:\n            estimator = self.estimator_list[0]\n            c = self._search_states[estimator].cat_hp_cost\n            return c\n        else:\n            configs = []\n            for estimator in self.estimator_list:\n                c = self._search_states[estimator].cat_hp_cost\n                configs.append(c)\n            configs.append(\n                [self._state.learner_classes.get(estimator).cost_relative2lgbm() for estimator in self.estimator_list]\n            )\n            config = {"ml": configs}\n        return config\n\n    @property\n    def points_to_evaluate(self) -> dict:\n        """Initial points to evaluate.\n\n        Returns:\n            A list of dicts. Each dict is the initial point for each learner.\n        """\n        points = []\n        for estimator in self.estimator_list:\n            configs = self._search_states[estimator].init_config\n            for config in configs:\n                config["learner"] = estimator\n                if len(self.estimator_list) > 1:\n                    points.append({"ml": config})\n                else:\n                    points.append(config)\n        return points\n\n    @property\n    def resource_attr(self) -> str | None:\n        """Attribute of the resource dimension.\n\n        Returns:\n            A string for the sample size attribute\n            (the resource attribute in AutoML) or None.\n        """\n        return "FLAML_sample_size" if self._sample else None\n\n    @property\n    def min_resource(self) -> float | None:\n        """Attribute for pruning.\n\n        Returns:\n            A float for the minimal sample size or None.\n        """\n        return self._min_sample_size if self._sample else None\n\n    @property\n    def max_resource(self) -> float | None:\n        """Attribute for pruning.\n\n        Returns:\n            A float for the maximal sample size or None.\n        """\n        return self._state.data_size[0] if self._sample else None\n\n    def pickle(self, output_file_name):\n        """Serialize the AutoML instance to a pickle file.\n\n        Notes:\n            When the trained estimator(s) are Spark-based, they may hold references\n            to SparkContext/SparkSession via Spark ML objects. Such objects are not\n            safely picklable and can cause pickling/broadcast errors.\n\n            This method externalizes Spark ML models into an adjacent artifact\n            directory and stores only lightweight metadata in the pickle.\n        """\n\n        import os\n        import pickle\n        import re\n\n        def _safe_name(name: str) -> str:\n            return re.sub(r"[^A-Za-z0-9_.-]+", "_", name)\n\n        def _iter_trained_estimators():\n            trained = getattr(self, "_trained_estimator", None)\n            if trained is not None:\n                yield "_trained_estimator", trained\n            for est_name in getattr(self, "estimator_list", []) or []:\n                ss = getattr(self, "_search_states", {}).get(est_name)\n                te = ss and getattr(ss, "trained_estimator", None)\n                if te is not None:\n                    yield f"_search_states.{est_name}.trained_estimator", te\n\n        def _scrub_pyspark_refs(root_obj):\n            """Best-effort removal of pyspark objects prior to pickling.\n\n            SparkContext/SparkSession and Spark DataFrame objects are not picklable.\n            This function finds such objects within common containers and instance\n            attributes and replaces them with None, returning a restore mapping.\n            """\n\n            try:\n                import pyspark\n                from pyspark.broadcast import Broadcast\n                from pyspark.sql import DataFrame as SparkDataFrame\n                from pyspark.sql import SparkSession\n\n                try:\n                    import pyspark.pandas as ps\n\n                    psDataFrameType = getattr(ps, "DataFrame", None)\n                    psSeriesType = getattr(ps, "Series", None)\n                except Exception:\n                    psDataFrameType = None\n                    psSeriesType = None\n\n                bad_types = [\n                    pyspark.SparkContext,\n                    SparkSession,\n                    SparkDataFrame,\n                    Broadcast,\n                ]\n                if psDataFrameType is not None:\n                    bad_types.append(psDataFrameType)\n                if psSeriesType is not None:\n                    bad_types.append(psSeriesType)\n                bad_types = tuple(t for t in bad_types if t is not None)\n            except Exception:\n                return {}\n\n            restore = {}\n            visited = set()\n\n            def _mark(parent, key, value, path):\n                restore[(id(parent), key)] = (parent, key, value)\n                try:\n                    if isinstance(parent, dict):\n                        parent[key] = None\n                    elif isinstance(parent, list):\n                        parent[key] = None\n                    elif isinstance(parent, tuple):\n                        # tuples are immutable; we can\'t modify in-place\n                        pass\n                    else:\n                        setattr(parent, key, None)\n                except Exception:\n                    # Best-effort.\n                    pass\n\n            def _walk(obj, depth, parent=None, key=None, path="self"):\n                if obj is None:\n                    return\n                oid = id(obj)\n                if oid in visited:\n                    return\n                visited.add(oid)\n\n                if isinstance(obj, bad_types):\n                    if parent is not None:\n                        _mark(parent, key, obj, path)\n                    return\n                if depth <= 0:\n                    return\n\n                if isinstance(obj, dict):\n                    for k, v in list(obj.items()):\n                        _walk(v, depth - 1, parent=obj, key=k, path=f"{path}[{k!r}]")\n                    return\n                if isinstance(obj, list):\n                    for i, v in enumerate(list(obj)):\n                        _walk(v, depth - 1, parent=obj, key=i, path=f"{path}[{i}]")\n                    return\n                if isinstance(obj, tuple):\n                    # Can\'t scrub inside tuples safely; but still inspect for diagnostics.\n                    for i, v in enumerate(obj):\n                        _walk(v, depth - 1, parent=None, key=None, path=f"{path}[{i}]")\n                    return\n                if isinstance(obj, set):\n                    for v in list(obj):\n                        _walk(v, depth - 1, parent=None, key=None, path=f"{path}{{...}}")\n                    return\n\n                d = getattr(obj, "__dict__", None)\n                if isinstance(d, dict):\n                    for attr, v in list(d.items()):\n                        _walk(v, depth - 1, parent=obj, key=attr, path=f"{path}.{attr}")\n\n            _walk(root_obj, depth=6)\n            return restore\n\n        # Temporarily remove non-picklable pieces (e.g., SparkContext-backed objects)\n        # and externalize spark models.\n        estimator_to_training_function = {}\n        spark_restore = []\n        artifact_dir = None\n        state_restore = {}\n        automl_restore = {}\n        scrub_restore = {}\n\n        try:\n            # Signatures are only used for MLflow logging; they are not required\n            # for inference and can capture SparkContext via pyspark objects.\n            for attr in ("estimator_signature", "pipeline_signature"):\n                if hasattr(self, attr):\n                    automl_restore[attr] = getattr(self, attr)\n                    setattr(self, attr, None)\n\n            for estimator in self.estimator_list:\n                search_state = self._search_states[estimator]\n                if hasattr(search_state, "training_function"):\n                    estimator_to_training_function[estimator] = search_state.training_function\n                    del search_state.training_function\n\n            # AutoMLState may keep Spark / pandas-on-Spark dataframes which are not picklable.\n            # They are not required for inference, so strip them for serialization.\n            state = getattr(self, "_state", None)\n            if state is not None:\n                for attr in (\n                    "X_train",\n                    "y_train",\n                    "X_train_all",\n                    "y_train_all",\n                    "X_val",\n                    "y_val",\n                    "weight_val",\n                    "groups_val",\n                    "sample_weight_all",\n                    "groups",\n                    "groups_all",\n                    "kf",\n                ):\n                    if hasattr(state, attr):\n                        state_restore[attr] = getattr(state, attr)\n                        setattr(state, attr, None)\n\n            for key, est in _iter_trained_estimators():\n                if getattr(est, "estimator_baseclass", None) != "spark":\n                    continue\n\n                # Drop training data reference (Spark DataFrame / pandas-on-Spark).\n                old_df_train = getattr(est, "df_train", None)\n                old_model = getattr(est, "_model", None)\n\n                model_meta = None\n                if old_model is not None:\n                    if artifact_dir is None:\n                        artifact_dir = output_file_name + ".flaml_artifacts"\n                        os.makedirs(artifact_dir, exist_ok=True)\n                        # store relative dirname so the pickle+folder can be moved together\n                        self._flaml_pickle_artifacts_dirname = os.path.basename(artifact_dir)\n\n                    model_dir = os.path.join(artifact_dir, _safe_name(key))\n                    # Spark ML models are saved as directories.\n                    try:\n                        writer = old_model.write()\n                        writer.overwrite().save(model_dir)\n                    except Exception as e:\n                        raise RuntimeError(\n                            "Failed to externalize Spark model for pickling. "\n                            "Please ensure the Spark ML model supports write().overwrite().save(path)."\n                        ) from e\n\n                    model_meta = {\n                        "path": os.path.relpath(model_dir, os.path.dirname(output_file_name) or "."),\n                        "class": old_model.__class__.__module__ + "." + old_model.__class__.__name__,\n                    }\n                    # Replace in-memory Spark model with metadata only.\n                    est._model = None\n                    est._flaml_spark_model_meta = model_meta\n\n                est.df_train = None\n                spark_restore.append((est, old_model, old_df_train, model_meta))\n\n            with open(output_file_name, "wb") as f:\n                try:\n                    pickle.dump(self, f, pickle.HIGHEST_PROTOCOL)\n                except Exception:\n                    # Some pyspark objects can still be captured indirectly.\n                    scrub_restore = _scrub_pyspark_refs(self)\n                    if scrub_restore:\n                        f.seek(0)\n                        f.truncate()\n                        pickle.dump(self, f, pickle.HIGHEST_PROTOCOL)\n                    else:\n                        raise\n        finally:\n            # Restore training_function and Spark models so current object remains usable.\n            for estimator, tf in estimator_to_training_function.items():\n                self._search_states[estimator].training_function = tf\n\n            for attr, val in automl_restore.items():\n                setattr(self, attr, val)\n\n            state = getattr(self, "_state", None)\n            if state is not None and state_restore:\n                for attr, val in state_restore.items():\n                    setattr(state, attr, val)\n\n            for est, old_model, old_df_train, model_meta in spark_restore:\n                est._model = old_model\n                est.df_train = old_df_train\n                if model_meta is not None and hasattr(est, "_flaml_spark_model_meta"):\n                    delattr(est, "_flaml_spark_model_meta")\n\n            if scrub_restore:\n                for _, (parent, key, value) in scrub_restore.items():\n                    try:\n                        if isinstance(parent, dict):\n                            parent[key] = value\n                        elif isinstance(parent, list):\n                            parent[key] = value\n                        else:\n                            setattr(parent, key, value)\n                    except Exception:\n                        pass\n\n    @classmethod\n    def load_pickle(cls, input_file_name: str, load_spark_models: bool = True):\n        """Load an AutoML instance saved by :meth:`pickle`.\n\n        Args:\n            input_file_name: Path to the pickle file created by :meth:`pickle`.\n            load_spark_models: Whether to load externalized Spark ML models back\n                into the estimator objects. If False, Spark estimators will remain\n                without their underlying Spark model and cannot be used for predict.\n\n        Returns:\n            The deserialized AutoML instance.\n        """\n        import importlib\n        import os\n        import pickle\n\n        with open(input_file_name, "rb") as f:\n            automl = pickle.load(f)\n\n        # Recreate per-estimator training_function if it was removed for pickling.\n        try:\n            for est_name, ss in getattr(automl, "_search_states", {}).items():\n                if not hasattr(ss, "training_function"):\n                    ss.training_function = partial(\n                        AutoMLState._compute_with_config_base,\n                        state=automl._state,\n                        estimator=est_name,\n                    )\n        except Exception:\n            # Best-effort; training_function is only needed for re-searching.\n            pass\n\n        if not load_spark_models:\n            return automl\n\n        base_dir = os.path.dirname(input_file_name) or "."\n\n        def _iter_trained_estimators_loaded():\n            trained = getattr(automl, "_trained_estimator", None)\n            if trained is not None:\n                yield trained\n            for ss in getattr(automl, "_search_states", {}).values():\n                te = ss and getattr(ss, "trained_estimator", None)\n                if te is not None:\n                    yield te\n\n        for est in _iter_trained_estimators_loaded():\n            meta = getattr(est, "_flaml_spark_model_meta", None)\n            if not meta:\n                continue\n            model_path = meta.get("path")\n            model_class = meta.get("class")\n            if not model_path or not model_class:\n                continue\n\n            abs_model_path = os.path.join(base_dir, model_path)\n\n            module_name, _, class_name = model_class.rpartition(".")\n            try:\n                module = importlib.import_module(module_name)\n                model_cls = getattr(module, class_name)\n            except Exception as e:\n                raise RuntimeError(f"Failed to import Spark model class \'{model_class}\'") from e\n\n            # Most Spark ML models support either Class.load(path) or Class.read().load(path).\n            if hasattr(model_cls, "load"):\n                est._model = model_cls.load(abs_model_path)\n            elif hasattr(model_cls, "read"):\n                est._model = model_cls.read().load(abs_model_path)\n            else:\n                try:\n                    from pyspark.ml.pipeline import PipelineModel\n\n                    loaded_model = PipelineModel.load(abs_model_path)\n                    if not isinstance(loaded_model, model_cls):\n                        raise RuntimeError(\n                            f"Loaded model type \'{type(loaded_model).__name__}\' does not match expected type \'{model_class}\'."\n                        )\n                    est._model = loaded_model\n                except Exception as e:\n                    raise RuntimeError(\n                        f"Spark model class \'{model_class}\' does not support load/read(). "\n                        "Unable to restore Spark model from artifacts."\n                    ) from e\n\n        return automl\n\n    @property\n    def trainable(self) -> Callable[[dict], float | None]:\n        """Training function.\n        Returns:\n            A function that evaluates each config and returns the loss.\n        """\n        self._state.time_from_start = 0\n        states = self._search_states\n        mem_res = self._mem_thres\n\n        def train(config: dict, state, is_report=True):\n            # handle spark broadcast variables\n            state = get_broadcast_data(state)\n            is_report = get_broadcast_data(is_report)\n            sample_size = config.get("FLAML_sample_size")\n            config = config.get("ml", config).copy()\n            if sample_size:\n                config["FLAML_sample_size"] = sample_size\n            estimator = config["learner"]\n            # check memory constraints before training\n            if states[estimator].learner_class.size(config) <= mem_res:\n                del config["learner"]\n                config.pop("_choice_", None)\n                result = AutoMLState._compute_with_config_base(\n                    config, state=state, estimator=estimator, is_report=is_report\n                )\n            else:\n                # If search algorithm is not in flaml, it does not handle the config constraint, should also tune.report before return\n                result = {\n                    "pred_time": 0,\n                    "wall_clock_time": None,\n                    "metric_for_logging": np.inf,\n                    "val_loss": np.inf,\n                    "trained_estimator": None,\n                }\n            if is_report is True:\n                tune.report(**result)\n            return result\n\n        if self._use_ray is not False:\n            from ray.tune import with_parameters\n\n            return with_parameters(\n                train,\n                state=self._state,\n            )\n        elif self._use_spark:\n            from flaml.tune.spark.utils import with_parameters\n\n            return with_parameters(train, state=self._state, is_report=False)\n        else:\n            return partial(\n                train,\n                state=self._state,\n            )\n\n    @property\n    def metric_constraints(self) -> list:\n        """Metric constraints.\n\n        Returns:\n            A list of the metric constraints.\n        """\n        return self._metric_constraints\n\n    def _prepare_data(self, eval_method, split_ratio, n_splits):\n        self._state.task.prepare_data(\n            self._state,\n            self._X_train_all,\n            self._y_train_all,\n            self._auto_augment,\n            eval_method,\n            self._split_type,\n            split_ratio,\n            n_splits,\n            self._df,\n            self._sample_weight_full,\n        )\n        self.data_size_full = self._state.data_size_full\n\n    def fit(\n        self,\n        X_train=None,\n        y_train=None,\n        dataframe=None,\n        label=None,\n        metric=None,\n        task: str | Task | None = None,\n        n_jobs=None,\n        # gpu_per_trial=0,\n        log_file_name=None,\n        estimator_list=None,\n        time_budget=None,\n        max_iter=None,\n        sample=None,\n        ensemble=None,\n        eval_method=None,\n        log_type=None,\n        model_history=None,\n        split_ratio=None,\n        n_splits=None,\n        log_training_metric=None,\n        mem_thres=None,\n        pred_time_limit=None,\n        train_time_limit=None,\n        X_val=None,\n        y_val=None,\n        sample_weight_val=None,\n        groups_val=None,\n        groups=None,\n        verbose=None,\n        retrain_full=None,\n        split_type=None,\n        learner_selector=None,\n        hpo_method=None,\n        starting_points=None,\n        seed=None,\n        n_concurrent_trials=None,\n        keep_search_state=None,\n        preserve_checkpoint=True,\n        early_stop=None,\n        force_cancel=None,\n        append_log=None,\n        auto_augment=None,\n        min_sample_size=None,\n        use_ray=None,\n        use_spark=None,\n        free_mem_ratio=0,\n        metric_constraints=None,\n        custom_hp=None,\n        time_col=None,\n        cv_score_agg_func=None,\n        skip_transform=None,\n        mlflow_logging=None,\n        fit_kwargs_by_estimator=None,\n        mlflow_exp_name=None,\n        **fit_kwargs,\n    ):\n        """Find a model for a given task.\n\n        Args:\n            X_train: A numpy array or a pandas dataframe of training data in\n                shape (n, m). For time series forecsat tasks, the first column of X_train\n                must be the timestamp column (datetime type). Other columns in\n                the dataframe are assumed to be exogenous variables (categorical or numeric).\n                When using ray, X_train can be a ray.ObjectRef.\n            y_train: A numpy array or a pandas series of labels in shape (n, ).\n            dataframe: A dataframe of training data including label column.\n                For time series forecast tasks, dataframe must be specified and must have\n                at least two columns, timestamp and label, where the first\n                column is the timestamp column (datetime type). Other columns in\n                the dataframe are assumed to be exogenous variables (categorical or numeric).\n                When using ray, dataframe can be a ray.ObjectRef.\n            label: A str of the label column name for, e.g., \'label\';\n                Note: If X_train and y_train are provided,\n                dataframe and label are ignored;\n                If not, dataframe and label must be provided.\n            metric: A string of the metric name or a function,\n                e.g., \'accuracy\', \'roc_auc\', \'roc_auc_ovr\', \'roc_auc_ovo\', \'roc_auc_weighted\',\n                \'roc_auc_ovo_weighted\', \'roc_auc_ovr_weighted\', \'f1\', \'micro_f1\', \'macro_f1\',\n                \'log_loss\', \'mae\', \'mse\', \'r2\', \'mape\'. Default is \'auto\'.\n                If passing a customized metric function, the function needs to\n                have the following input arguments:\n\n        ```python\n        def custom_metric(\n            X_test, y_test, estimator, labels,\n            X_train, y_train, weight_test=None, weight_train=None,\n            config=None, groups_test=None, groups_train=None,\n        ):\n            return metric_to_minimize, metrics_to_log\n        ```\n                which returns a float number as the minimization objective,\n                and a dictionary as the metrics to log. E.g.,\n\n        ```python\n        def custom_metric(\n            X_val, y_val, estimator, labels,\n            X_train, y_train, weight_val=None, weight_train=None,\n            *args,\n        ):\n            from sklearn.metrics import log_loss\n            import time\n\n            start = time.time()\n            y_pred = estimator.predict_proba(X_val)\n            pred_time = (time.time() - start) / len(X_val)\n            val_loss = log_loss(y_val, y_pred, labels=labels, sample_weight=weight_val)\n            y_pred = estimator.predict_proba(X_train)\n            train_loss = log_loss(y_train, y_pred, labels=labels, sample_weight=weight_train)\n            alpha = 0.5\n            return val_loss * (1 + alpha) - alpha * train_loss, {\n                "val_loss": val_loss,\n                "train_loss": train_loss,\n                "pred_time": pred_time,\n            }\n        ```\n            task: A string of the task type, e.g.,\n                \'classification\', \'regression\', \'ts_forecast_regression\',\n                \'ts_forecast_classification\', \'rank\', \'seq-classification\',\n                \'seq-regression\', \'summarization\', or an instance of Task class\n            n_jobs: An integer of the number of threads for training | default=-1.\n                Use all available resources when n_jobs == -1.\n            log_file_name: A string of the log file name | default="". To disable logging,\n                set it to be an empty string "".\n            estimator_list: A list of strings for estimator names, or \'auto\'.\n                e.g., ```[\'lgbm\', \'xgboost\', \'xgb_limitdepth\', \'catboost\', \'rf\', \'extra_tree\']```.\n            time_budget: A float number of the time budget in seconds.\n                Use -1 if no time limit.\n            max_iter: An integer of the maximal number of iterations.\n                NOTE: when both time_budget and max_iter are unspecified,\n                only one model will be trained per estimator.\n            sample: A boolean of whether to sample the training data during\n                search.\n            ensemble: boolean or dict | default=False. Whether to perform\n                ensemble after search. Can be a dict with keys \'passthrough\'\n                and \'final_estimator\' to specify the passthrough and\n                final_estimator in the stacker. The dict can also contain\n                \'n_jobs\' as the key to specify the number of jobs for the stacker.\n            eval_method: A string of resampling strategy, one of\n                [\'auto\', \'cv\', \'holdout\'].\n            split_ratio: A float of the valiation data percentage for holdout.\n            n_splits: An integer of the number of folds for cross - validation.\n            log_type: A string of the log type, one of\n                [\'better\', \'all\'].\n                \'better\' only logs configs with better loss than previos iters\n                \'all\' logs all the tried configs.\n            model_history: A boolean of whether to keep the trained best\n                model per estimator. Make sure memory is large enough if setting to True.\n                Default value is False. If False, best_model_for_estimator would return a\n                untrained model for non-best learner.\n            log_training_metric: A boolean of whether to log the training\n                metric for each model.\n            mem_thres: A float of the memory size constraint in bytes.\n            pred_time_limit: A float of the prediction latency constraint in seconds.\n                It refers to the average prediction time per row in validation data.\n            train_time_limit: None or a float of the training time constraint in seconds for each trial.\n                Only valid for sequential search.\n            X_val: None or a numpy array or a pandas dataframe of validation data.\n            y_val: None or a numpy array or a pandas series of validation labels.\n            sample_weight_val: None or a numpy array of the sample weight of\n                validation data of the same shape as y_val.\n            groups_val: None or array-like | group labels (with matching length\n                to y_val) or group counts (with sum equal to length of y_val)\n                for validation data. Need to be consistent with groups.\n            groups: None or array-like | Group labels (with matching length to\n                y_train) or groups counts (with sum equal to length of y_train)\n                for training data.\n            verbose: int, default=3 | Controls the verbosity, higher means more\n                messages.\n                verbose=0: logger level = CRITICAL\n                verbose=1: logger level = ERROR\n                verbose=2: logger level = WARNING\n                verbose=3: logger level = INFO\n                verbose=4: logger level = DEBUG\n                verbose>5: logger level = NOTSET\n            retrain_full: bool or str, default=True | whether to retrain the\n                selected model on the full training data when using holdout.\n                True - retrain only after search finishes; False - no retraining;\n                \'budget\' - do best effort to retrain without violating the time\n                budget.\n            split_type: str or splitter object, default="auto" | the data split type.\n                * A valid splitter object is an instance of a derived class of scikit-learn\n                [KFold](https://scikit-learn.org/stable/modules/generated/sklearn.model_selection.KFold.html#sklearn.model_selection.KFold)\n                and have ``split`` and ``get_n_splits`` methods with the same signatures.\n                Set eval_method to "cv" to use the splitter object.\n                * Valid str options depend on different tasks.\n                For classification tasks, valid choices are\n                    ["auto", \'stratified\', \'uniform\', \'time\', \'group\']. "auto" -> stratified.\n                For regression tasks, valid choices are ["auto", \'uniform\', \'time\', \'group\'].\n                    "auto" -> uniform.\n                For time series forecast tasks, must be "auto" or \'time\'.\n                For ranking task, must be "auto" or \'group\'.\n            hpo_method: str, default="auto" | The hyperparameter\n                optimization method. By default, CFO is used for sequential\n                search and BlendSearch is used for parallel search.\n                No need to set when using flaml\'s default search space or using\n                a simple customized search space. When set to \'bs\', BlendSearch\n                is used. BlendSearch can be tried when the search space is\n                complex, for example, containing multiple disjoint, discontinuous\n                subspaces. When set to \'random\', random search is used.\n            starting_points: A dictionary or a str to specify the starting hyperparameter\n                config for the estimators | default="data".\n                If str:\n                    - if "data", use data-dependent defaults;\n                    - if "data:path" use data-dependent defaults which are stored at path;\n                    - if "static", use data-independent defaults.\n                If dict, keys are the name of the estimators, and values are the starting\n                hyperparameter configurations for the corresponding estimators.\n                The value can be a single hyperparameter configuration dict or a list\n                of hyperparameter configuration dicts.\n                In the following code example, we get starting_points from the\n                `automl` object and use them in the `new_automl` object.\n                e.g.,\n\n        ```python\n        from flaml import AutoML\n        automl = AutoML()\n        X_train, y_train = load_iris(return_X_y=True)\n        automl.fit(X_train, y_train)\n        starting_points = automl.best_config_per_estimator\n\n        new_automl = AutoML()\n        new_automl.fit(X_train, y_train, starting_points=starting_points)\n        ```\n\n            seed: int or None, default=None | The random seed for hpo.\n            n_concurrent_trials: [In preview] int, default=1 | The number of\n                concurrent trials. When n_concurrent_trials > 1, flaml performes\n                [parallel tuning](/docs/Use-Cases/Task-Oriented-AutoML#parallel-tuning)\n                and installation of ray or spark is required: `pip install flaml[ray]`\n                or `pip install flaml[spark]`. Please check\n                [here](https://spark.apache.org/docs/latest/api/python/getting_started/install.html)\n                for more details about installing Spark.\n            keep_search_state: boolean, default=False | Whether to keep data needed\n                for model search after fit(). By default the state is deleted for\n                space saving.\n            preserve_checkpoint: boolean, default=True | Whether to preserve the saved checkpoint\n                on disk when deleting automl. By default the checkpoint is preserved.\n            early_stop: boolean, default=False | Whether to stop early if the\n                search is considered to converge.\n            force_cancel: boolean, default=False | Whether to forcely cancel the PySpark job if overtime.\n            mlflow_exp_name: str, default=None | The name of the mlflow experiment. This should be specified if\n                enable mlflow autologging on Spark. Otherwise it will log all the results into the experiment of the\n                same name as the basename of main entry file.\n            append_log: boolean, default=False | Whetehr to directly append the log\n                records to the input log file if it exists.\n            auto_augment: boolean, default=True | Whether to automatically\n                augment rare classes.\n            min_sample_size: int, default=MIN_SAMPLE_TRAIN | the minimal sample\n                size when sample=True.\n            use_ray: boolean or dict.\n                If boolean: default=False | Whether to use ray to run the training\n                in separate processes. This can be used to prevent OOM for large\n                datasets, but will incur more overhead in time.\n                If dict: the dict contains the keywords arguments to be passed to\n                [ray.tune.run](https://docs.ray.io/en/latest/tune/api_docs/execution.html).\n            use_spark: boolean, default=False | Whether to use spark to run the training\n                in parallel spark jobs. This can be used to accelerate training on large models\n                and large datasets, but will incur more overhead in time and thus slow down\n                training in some cases.\n            free_mem_ratio: float between 0 and 1, default=0. The free memory ratio to keep during training.\n            metric_constraints: list, default=[] | The list of metric constraints.\n                Each element in this list is a 3-tuple, which shall be expressed\n                in the following format: the first element of the 3-tuple is the name of the\n                metric, the second element is the inequality sign chosen from ">=" and "<=",\n                and the third element is the constraint value. E.g., `(\'precision\', \'>=\', 0.9)`.\n                Note that all the metric names in metric_constraints need to be reported via\n                the metrics_to_log dictionary returned by a customized metric function.\n                The customized metric function shall be provided via the `metric` key word argument\n                of the fit() function or the automl constructor.\n                Find examples in this [test](https://github.com/microsoft/FLAML/tree/main/test/automl/test_constraints.py).\n                If `pred_time_limit` is provided as one of keyword arguments to fit() function or\n                the automl constructor, flaml will automatically (and under the hood)\n                add it as an additional element in the metric_constraints. Essentially \'pred_time_limit\'\n                specifies a constraint about the prediction latency constraint in seconds.\n            custom_hp: dict, default=None | The custom search space specified by user\n                Each key is the estimator name, each value is a dict of the custom search space for that estimator. Notice the\n                domain of the custom search space can either be a value of a sample.Domain object.\n\n\n\n        ```python\n        custom_hp = {\n            "transformer_ms": {\n                "model_path": {\n                    "domain": "albert-base-v2",\n                },\n                "learning_rate": {\n                    "domain": tune.choice([1e-4, 1e-5]),\n                }\n            }\n        }\n        ```\n            time_col: for a time series task, name of the column containing the timestamps. If not\n                provided, defaults to the first column of X_train/X_val\n\n            cv_score_agg_func: customized cross-validation scores aggregate function. Default to average metrics across folds. If specificed, this function needs to\n                have the following input arguments:\n\n                * val_loss_folds: list of floats, the loss scores of each fold;\n                * log_metrics_folds: list of dicts/floats, the metrics of each fold to log.\n\n                This function should return the final aggregate result of all folds. A float number of the minimization objective, and a dictionary as the metrics to log or None.\n                    E.g.,\n\n        ```python\n        def cv_score_agg_func(val_loss_folds, log_metrics_folds):\n            metric_to_minimize = sum(val_loss_folds)/len(val_loss_folds)\n            metrics_to_log = None\n            for single_fold in log_metrics_folds:\n                if metrics_to_log is None:\n                    metrics_to_log = single_fold\n                elif isinstance(metrics_to_log, dict):\n                    metrics_to_log = {k: metrics_to_log[k] + v for k, v in single_fold.items()}\n                else:\n                    metrics_to_log += single_fold\n            if metrics_to_log:\n                n = len(val_loss_folds)\n                metrics_to_log = (\n                    {k: v / n for k, v in metrics_to_log.items()}\n                    if isinstance(metrics_to_log, dict)\n                    else metrics_to_log / n\n                )\n            return metric_to_minimize, metrics_to_log\n        ```\n\n            skip_transform: boolean, default=False | Whether to pre-process data prior to modeling.\n            mlflow_logging: boolean, default=None | Whether to log the training results to mlflow.\n                Default value is None, which means the logging decision is made based on\n                AutoML.__init__\'s mlflow_logging argument. Not valid if mlflow is not installed.\n            fit_kwargs_by_estimator: dict, default=None | The user specified keywords arguments, grouped by estimator name.\n                For TransformersEstimator, available fit_kwargs can be found from\n                [TrainingArgumentsForAuto](nlp/huggingface/training_args).\n                e.g.,\n\n        ```python\n        fit_kwargs_by_estimator = {\n            "transformer": {\n                "output_dir": "test/data/output/",\n                "fp16": False,\n            },\n            "tft": {\n                "max_encoder_length": 1,\n                "min_encoder_length": 1,\n                "static_categoricals": [],\n                "static_reals": [],\n                "time_varying_known_categoricals": [],\n                "time_varying_known_reals": [],\n                "time_varying_unknown_categoricals": [],\n                "time_varying_unknown_reals": [],\n                "variable_groups": {},\n                "lags": {},\n            }\n        }\n        ```\n\n            **fit_kwargs: Other key word arguments to pass to fit() function of\n                the searched learners, such as sample_weight. Below are a few examples of\n                estimator-specific parameters:\n                    period: int | forecast horizon for all time series forecast tasks.\n                    gpu_per_trial: float, default = 0 | A float of the number of gpus per trial,\n                        only used by TransformersEstimator, XGBoostSklearnEstimator, and\n                        TemporalFusionTransformerEstimator.\n                    group_ids: list of strings of column names identifying a time series, only\n                        used by TemporalFusionTransformerEstimator, required for\n                        \'ts_forecast_panel\' task. `group_ids` is a parameter for TimeSeriesDataSet object\n                        from PyTorchForecasting.\n                        For other parameters to describe your dataset, refer to\n                        [TimeSeriesDataSet PyTorchForecasting](https://pytorch-forecasting.readthedocs.io/en/stable/api/pytorch_forecasting.data.timeseries.TimeSeriesDataSet.html).\n                        To specify your variables, use `static_categoricals`, `static_reals`,\n                        `time_varying_known_categoricals`, `time_varying_known_reals`,\n                        `time_varying_unknown_categoricals`, `time_varying_unknown_reals`,\n                        `variable_groups`. To provide more information on your data, use\n                        `max_encoder_length`, `min_encoder_length`, `lags`.\n                    log_dir: str, default = "lightning_logs" | Folder into which to log results\n                        for tensorboard, only used by TemporalFusionTransformerEstimator.\n                    max_epochs: int, default = 20 | Maximum number of epochs to run training,\n                        only used by TemporalFusionTransformerEstimator.\n                    batch_size: int, default = 64 | Batch size for training model, only\n                        used by TemporalFusionTransformerEstimator and TCNEstimator.\n        """\n\n        self._state._start_time_flag = self._start_time_flag = time.time()\n        task = task or self._settings.get("task")\n        if isinstance(task, str):\n            task = task_factory(task, X_train, y_train)\n        self._state.task = task\n        self._state.task.time_col = time_col\n        self._estimator_type = "classifier" if task.is_classification() else "regressor"\n        time_budget = time_budget or self._settings.get("time_budget")\n        n_jobs = n_jobs or self._settings.get("n_jobs")\n        gpu_per_trial = fit_kwargs.get("gpu_per_trial", 0)\n        eval_method = eval_method or self._settings.get("eval_method")\n        split_ratio = split_ratio or self._settings.get("split_ratio")\n        n_splits = n_splits or self._settings.get("n_splits")\n        auto_augment = self._settings.get("auto_augment") if auto_augment is None else auto_augment\n        metric = metric or self._settings.get("metric")\n        estimator_list = estimator_list or self._settings.get("estimator_list")\n        log_file_name = self._settings.get("log_file_name") if log_file_name is None else log_file_name\n        max_iter = self._settings.get("max_iter") if max_iter is None else max_iter\n        sample_is_none = sample is None\n        if sample_is_none:\n            sample = self._settings.get("sample")\n        ensemble = self._settings.get("ensemble") if ensemble is None else ensemble\n        log_type = log_type or self._settings.get("log_type")\n        model_history = self._settings.get("model_history") if model_history is None else model_history\n        log_training_metric = (\n            self._settings.get("log_training_metric") if log_training_metric is None else log_training_metric\n        )\n        mem_thres = mem_thres or self._settings.get("mem_thres")\n        pred_time_limit = pred_time_limit or self._settings.get("pred_time_limit")\n        train_time_limit = train_time_limit or self._settings.get("train_time_limit")\n        self._metric_constraints = metric_constraints or self._settings.get("metric_constraints")\n        if np.isfinite(pred_time_limit):\n            self._metric_constraints.append(("pred_time", "<=", pred_time_limit))\n        verbose = self._settings.get("verbose") if verbose is None else verbose\n        retrain_full = self._settings.get("retrain_full") if retrain_full is None else retrain_full\n        split_type = split_type or self._settings.get("split_type")\n        hpo_method = hpo_method or self._settings.get("hpo_method")\n        learner_selector = learner_selector or self._settings.get("learner_selector")\n        no_starting_points = starting_points is None\n        if no_starting_points:\n            starting_points = self._settings.get("starting_points")\n        n_concurrent_trials = n_concurrent_trials or self._settings.get("n_concurrent_trials")\n        keep_search_state = self._settings.get("keep_search_state") if keep_search_state is None else keep_search_state\n        self.preserve_checkpoint = (\n            self._settings.get("preserve_checkpoint") if preserve_checkpoint is None else preserve_checkpoint\n        )\n        early_stop = self._settings.get("early_stop") if early_stop is None else early_stop\n        force_cancel = self._settings.get("force_cancel") if force_cancel is None else force_cancel\n        mlflow_exp_name = self._settings.get("mlflow_exp_name") if mlflow_exp_name is None else mlflow_exp_name\n        # no search budget is provided?\n        no_budget = time_budget < 0 and max_iter is None and not early_stop\n        append_log = self._settings.get("append_log") if append_log is None else append_log\n        min_sample_size = min_sample_size or self._settings.get("min_sample_size")\n        use_ray = self._settings.get("use_ray") if use_ray is None else use_ray\n        use_spark = self._settings.get("use_spark") if use_spark is None else use_spark\n        if use_spark and use_ray is not False:\n            raise ValueError("use_spark and use_ray cannot be both True.")\n        elif use_spark:\n            spark_available, spark_error_msg = check_spark()\n            if not spark_available:\n                raise spark_error_msg\n\n        old_level = logger.getEffectiveLevel()\n        self.verbose = verbose\n        logger.setLevel(50 - verbose * 10)\n        if not logger.handlers:\n            # Add the console handler.\n            _ch = logging.StreamHandler(stream=sys.stdout)\n            _ch.setFormatter(logger_formatter)\n            logger.addHandler(_ch)\n\n        if model_history:\n            logger.warning(\n                "With `model_history` set to `True` by default, all intermediate models are retained in memory, "\n                "which may significantly increase memory usage and slow down training. "\n                "Consider setting `model_history=False` to optimize memory and accelerate the training process."\n            )\n\n        if not use_ray and not use_spark and n_concurrent_trials > 1:\n            if ray_available:\n                logger.warning(\n                    "n_concurrent_trials > 1 is only supported when using Ray or Spark. "\n                    "Ray installed, setting use_ray to True. If you want to use Spark, set use_spark to True."\n                )\n                use_ray = True\n            else:\n                spark_available, _ = check_spark()\n                if spark_available:\n                    logger.warning(\n                        "n_concurrent_trials > 1 is only supported when using Ray or Spark. "\n                        "Spark installed, setting use_spark to True. If you want to use Ray, set use_ray to True."\n                    )\n                    use_spark = True\n                else:\n                    logger.warning(\n                        "n_concurrent_trials > 1 is only supported when using Ray or Spark. "\n                        "Neither Ray nor Spark installed, setting n_concurrent_trials to 1."\n                    )\n                    n_concurrent_trials = 1\n\n        self._state.n_jobs = n_jobs\n        self._n_concurrent_trials = n_concurrent_trials\n        self._early_stop = early_stop\n        self._use_spark = use_spark\n        self._force_cancel = force_cancel\n        self._use_ray = use_ray\n        # use the following condition if we have an estimation of average_trial_time and average_trial_overhead\n        # self._use_ray = use_ray or n_concurrent_trials > ( average_trial_time + average_trial_overhead) / (average_trial_time)\n        if self._use_ray is not False:\n            import ray\n\n            n_cpus = ray.is_initialized() and ray.available_resources()["CPU"] or os.cpu_count()\n\n            self._state.resources_per_trial = (\n                # when using gpu, default cpu is 1 per job; otherwise, default cpu is n_cpus / n_concurrent_trials\n                (\n                    {\n                        "cpu": max(int((n_cpus - 2) / 2 / n_concurrent_trials), 1),\n                        "gpu": gpu_per_trial,\n                    }\n                    if gpu_per_trial == 0\n                    else {"cpu": 1, "gpu": gpu_per_trial}\n                )\n                if n_jobs < 0\n                else {"cpu": n_jobs, "gpu": gpu_per_trial}\n            )\n\n            if isinstance(X_train, ray.ObjectRef):\n                X_train = ray.get(X_train)\n            elif isinstance(dataframe, ray.ObjectRef):\n                dataframe = ray.get(dataframe)\n        else:\n            # TODO: Integrate with Spark\n            self._state.resources_per_trial = {"cpu": n_jobs} if n_jobs > 0 else {"cpu": 1}\n        self._state.free_mem_ratio = self._settings.get("free_mem_ratio") if free_mem_ratio is None else free_mem_ratio\n        self._state.task = task\n        self._state.log_training_metric = log_training_metric\n\n        self._state.fit_kwargs = fit_kwargs\n        custom_hp = custom_hp or self._settings.get("custom_hp")\n        self._skip_transform = self._settings.get("skip_transform") if skip_transform is None else skip_transform\n        self._mlflow_logging = (\n            False\n            if mlflow is None\n            else self._settings.get("mlflow_logging")\n            if mlflow_logging is None\n            else mlflow_logging\n        )\n        fit_kwargs_by_estimator = fit_kwargs_by_estimator or self._settings.get("fit_kwargs_by_estimator")\n        self._state.fit_kwargs_by_estimator = fit_kwargs_by_estimator.copy()  # shallow copy of fit_kwargs_by_estimator\n        self._state.weight_val = sample_weight_val\n        self._mlflow_exp_name = mlflow_exp_name\n        self.mlflow_integration = None\n        self.autolog_extra_tag = {\n            "extra_tag.sid": f"flaml_{flaml_version}_{int(time.time())}_{random.randint(1001, 9999)}"\n        }\n        if internal_mlflow and self._mlflow_logging and (mlflow.active_run() or is_autolog_enabled()):\n            try:\n                self.mlflow_integration = MLflowIntegration("automl", mlflow_exp_name, extra_tag=self.autolog_extra_tag)\n                self._mlflow_exp_name = self.mlflow_integration.experiment_name\n                if not (mlflow.active_run() is not None or is_autolog_enabled()):\n                    self.mlflow_integration.only_history = True\n            except KeyError:\n                logger.info("Not in Fabric, Skipped")\n        task.validate_data(\n            self,\n            self._state,\n            X_train,\n            y_train,\n            dataframe,\n            label,\n            X_val,\n            y_val,\n            groups_val,\n            groups,\n        )\n        self._search_states = {}  # key: estimator name; value: SearchState\n        self._random = np.random.RandomState(RANDOM_SEED)\n        self._seed = seed if seed is not None else 20\n        self._learner_selector = learner_selector\n        logger.info(f"task = {task}")\n        self._split_type = self._state.task.decide_split_type(\n            split_type,\n            self._y_train_all,\n            self._state.fit_kwargs,\n            self._state.groups,\n        )\n        if X_val is not None:\n            logger.info(f"Data split method: {self._split_type}")\n        eval_method = self._decide_eval_method(eval_method, time_budget)\n        self._state.eval_method = eval_method\n        logger.info(f"Evaluation method: {eval_method}")\n        self._state.cv_score_agg_func = cv_score_agg_func or self._settings.get("cv_score_agg_func")\n\n        self._retrain_in_budget = retrain_full == "budget" and (eval_method == "holdout" and self._state.X_val is None)\n        self._auto_augment = auto_augment\n\n        _sample_size_from_starting_points = {}\n        if isinstance(starting_points, dict):\n            for _estimator, _point_per_estimator in starting_points.items():\n                sample_size = (\n                    _point_per_estimator\n                    and isinstance(_point_per_estimator, dict)\n                    and _point_per_estimator.get("FLAML_sample_size")\n                )\n                if sample_size:\n                    _sample_size_from_starting_points[_estimator] = sample_size\n                elif _point_per_estimator and isinstance(_point_per_estimator, list):\n                    _sample_size_set = {\n                        config["FLAML_sample_size"] for config in _point_per_estimator if "FLAML_sample_size" in config\n                    }\n                    if _sample_size_set:\n                        _sample_size_from_starting_points[_estimator] = min(_sample_size_set)\n                    if len(_sample_size_set) > 1:\n                        logger.warning(\n                            "Using the min FLAML_sample_size of all the provided starting points for estimator {}. (Provided FLAML_sample_size are: {})".format(\n                                _estimator, _sample_size_set\n                            )\n                        )\n\n        if not sample and isinstance(starting_points, dict):\n            assert (\n                not _sample_size_from_starting_points\n            ), "When subsampling is disabled, do not include FLAML_sample_size in the starting point."\n        self._min_sample_size = _sample_size_from_starting_points or min_sample_size\n        self._min_sample_size_input = min_sample_size\n        self._prepare_data(eval_method, split_ratio, n_splits)\n\n        # infer the signature of the input/output data\n        if self.mlflow_integration is not None:\n            self.estimator_signature = infer_signature(self._state.X_train, self._state.y_train)\n            self.pipeline_signature = infer_signature(X_train, y_train, dataframe, label)\n\n        # TODO pull this to task as decide_sample_size\n        if isinstance(self._min_sample_size, dict):\n            self._sample = {\n                (\n                    k,\n                    sample\n                    and not task.is_rank()\n                    and eval_method != "cv"\n                    and (self._min_sample_size[k] * SAMPLE_MULTIPLY_FACTOR < self._state.data_size[0]),\n                )\n                for k in self._min_sample_size.keys()\n            }\n        else:\n            self._sample = (\n                sample\n                and not task.is_rank()\n                and eval_method != "cv"\n                and (self._min_sample_size * SAMPLE_MULTIPLY_FACTOR < self._state.data_size[0])\n            )\n\n        metric = task.default_metric(metric)\n        self._state.metric = metric\n\n        # TODO pull this to task\n        def is_to_reverse_metric(metric, task):\n            if metric.startswith("ndcg"):\n                return True, f"1-{metric}"\n            if metric in [\n                "r2",\n                "accuracy",\n                "roc_auc",\n                "roc_auc_ovr",\n                "roc_auc_ovo",\n                "roc_auc_weighted",\n                "roc_auc_ovr_weighted",\n                "roc_auc_ovo_weighted",\n                "f1",\n                "ap",\n                "micro_f1",\n                "macro_f1",\n            ]:\n                return True, f"1-{metric}"\n            if task.is_nlp():\n                from flaml.automl.ml import huggingface_metric_to_mode\n\n                if metric in huggingface_metric_to_mode and huggingface_metric_to_mode[metric] == "max":\n                    return True, f"-{metric}"\n            return False, None\n\n        if isinstance(metric, str):\n            is_reverse, reverse_metric = is_to_reverse_metric(metric, task)\n            if is_reverse:\n                error_metric = reverse_metric\n            else:\n                error_metric = metric\n        else:\n            error_metric = "customized metric"\n        logger.info(f"Minimizing error metric: {error_metric}")\n        self._state.error_metric = error_metric\n\n        is_spark_dataframe = isinstance(X_train, psDataFrame) or isinstance(dataframe, psDataFrame)\n        estimator_list = task.default_estimator_list(estimator_list, is_spark_dataframe)\n\n        if is_spark_dataframe and self._use_spark:\n            # For spark dataframe, use_spark must be False because spark models are trained in parallel themselves\n            self._use_spark = False\n            logger.warning(\n                "Spark dataframes support only spark.ml type models, which will be trained "\n                "with spark themselves, no need to start spark trials in flaml. "\n                "`use_spark` is set to False."\n            )\n\n        # When no search budget is specified\n        if no_budget:\n            max_iter = len(estimator_list)\n            self._learner_selector = "roundrobin"\n            if sample_is_none:\n                self._sample = False\n            if no_starting_points:\n                starting_points = "data"\n            logger.warning(\n                "No search budget is provided via time_budget or max_iter."\n                " Training only one model per estimator."\n                " Zero-shot AutoML is used for certain tasks and estimators."\n                " To tune hyperparameters for each estimator,"\n                " please provide budget either via time_budget or max_iter."\n            )\n        elif max_iter is None:\n            # set to a large number\n            max_iter = 1000000\n        self._state.retrain_final = (\n            retrain_full is True\n            and eval_method == "holdout"\n            and (X_val is None or self._use_ray is not False)\n            or eval_method == "cv"\n            and (max_iter > 0 or retrain_full is True)\n            or max_iter == 1\n        )\n        if self.mlflow_integration is not None and all(\n            [self.mlflow_integration.parent_run_id is None, not self.mlflow_integration.only_history]\n        ):\n            # force not retrain if no active run\n            self._state.retrain_final = False\n        # add custom learner\n        for estimator_name in estimator_list:\n            if estimator_name not in self._state.learner_classes:\n                self.add_learner(\n                    estimator_name,\n                    self._state.task.estimator_class_from_str(estimator_name),\n                )\n        # set up learner search space\n        if isinstance(starting_points, str) and starting_points.startswith("data"):\n            from flaml.default import suggest_config\n\n            location = starting_points[5:]\n            starting_points = {}\n            for estimator_name in estimator_list:\n                try:\n                    configs = suggest_config(\n                        self._state.task,\n                        self._X_train_all,\n                        self._y_train_all,\n                        estimator_name,\n                        location,\n                        k=1,\n                    )\n                    starting_points[estimator_name] = [x["hyperparameters"] for x in configs]\n                except FileNotFoundError:\n                    pass\n            try:\n                learner = suggest_learner(\n                    self._state.task,\n                    self._X_train_all,\n                    self._y_train_all,\n                    estimator_list=estimator_list,\n                    location=location,\n                )\n                if learner != estimator_list[0]:\n                    estimator_list.remove(learner)\n                    estimator_list.insert(0, learner)\n            except FileNotFoundError:\n                pass\n\n        self._state.time_budget = time_budget\n        starting_points = {} if starting_points == "static" else starting_points\n        for estimator_name in estimator_list:\n            estimator_class = self._state.learner_classes[estimator_name]\n            estimator_class.init()\n            this_estimator_kwargs = self._state.fit_kwargs_by_estimator.get(estimator_name)\n            if this_estimator_kwargs:\n                # make another shallow copy of the value (a dict obj), so user\'s fit_kwargs_by_estimator won\'t be updated\n                this_estimator_kwargs = this_estimator_kwargs.copy()\n                this_estimator_kwargs.update(\n                    self._state.fit_kwargs\n                )  # update the shallow copy of fit_kwargs to fit_kwargs_by_estimator\n                self._state.fit_kwargs_by_estimator[\n                    estimator_name\n                ] = this_estimator_kwargs  # set self._state.fit_kwargs_by_estimator[estimator_name] to the update, so only self._state.fit_kwargs_by_estimator will be updated\n            else:\n                self._state.fit_kwargs_by_estimator[estimator_name] = self._state.fit_kwargs\n\n            self._search_states[estimator_name] = SearchState(\n                learner_class=estimator_class,\n                # data_size=self._state.data_size,\n                data=self._state.X_train,\n                task=self._state.task,\n                starting_point=starting_points.get(estimator_name),\n                period=self._state.fit_kwargs.get(\n                    "period"\n                ),  # NOTE: this is after kwargs is updated to fit_kwargs_by_estimator\n                custom_hp=custom_hp and custom_hp.get(estimator_name),\n                max_iter=max_iter / len(estimator_list) if self._learner_selector == "roundrobin" else max_iter,\n                budget=self._state.time_budget,\n            )\n        logger.info(f"List of ML learners in AutoML Run: {estimator_list}")\n        self.estimator_list = estimator_list\n        self._active_estimators = estimator_list.copy()\n        self._ensemble = ensemble\n        self._max_iter = max_iter\n        self._mem_thres = mem_thres\n        self._pred_time_limit = pred_time_limit\n        self._state.train_time_limit = train_time_limit\n        self._log_type = log_type\n        self.split_ratio = split_ratio\n        self._state.model_history = model_history\n        self._hpo_method = (\n            hpo_method\n            if hpo_method != "auto"\n            else (\n                "bs"\n                if n_concurrent_trials > 1\n                or (self._use_ray is not False or self._use_spark)\n                and len(estimator_list) > 1\n                else "cfo"\n            )\n        )\n        if log_file_name:\n            with training_log_writer(log_file_name, append_log) as save_helper:\n                self._training_log = save_helper\n                self._search()\n        else:\n            self._training_log = None\n            self._search()\n        if self._best_estimator:\n            logger.info("fit succeeded")\n            logger.info(f"Time taken to find the best model: {self._time_taken_best_iter}")\n            if (\n                self._hpo_method in ("cfo", "bs")\n                and self._state.time_budget > 0\n                and (self._time_taken_best_iter >= self._state.time_budget * 0.7)\n                and not all(\n                    state.search_alg and state.search_alg.searcher.is_ls_ever_converged\n                    for state in self._search_states.values()\n                )\n            ):\n                logger.warning(\n                    "Time taken to find the best model is {:.0f}% of the "\n                    "provided time budget and not all estimators\' hyperparameter "\n                    "search converged. Consider increasing the time budget.".format(\n                        self._time_taken_best_iter / self._state.time_budget * 100\n                    )\n                )\n\n        if not keep_search_state:\n            # release space\n            del self._X_train_all, self._y_train_all, self._state.kf\n            del self._state.X_train, self._state.X_train_all, self._state.X_val\n            del self._state.y_train, self._state.y_train_all, self._state.y_val\n            del (\n                self._sample_weight_full,\n                self._state.fit_kwargs_by_estimator,\n                self._state.fit_kwargs,\n            )  # NOTE: this is after kwargs is updated to fit_kwargs_by_estimator\n            del self._state.groups, self._state.groups_all, self._state.groups_val\n        logger.setLevel(old_level)\n        if self.mlflow_integration is not None:\n            self.mlflow_integration.resume_mlflow()\n\n    def _search_parallel(self):\n        if self._use_ray is not False:\n            try:\n                from ray import __version__ as ray_version\n\n                assert ray_version >= "1.10.0"\n                if ray_version.startswith("1."):\n                    from ray.tune.suggest import ConcurrencyLimiter\n                else:\n                    from ray.tune.search import ConcurrencyLimiter\n                import ray\n            except (ImportError, AssertionError):\n                raise ImportError("use_ray=True requires installation of ray. " "Please run pip install flaml[ray]")\n        else:\n            from flaml.tune.searcher.suggestion import ConcurrencyLimiter\n\n        if self._hpo_method in ("cfo", "grid"):\n            from flaml import CFO as SearchAlgo\n        elif "bs" == self._hpo_method:\n            from flaml import BlendSearch as SearchAlgo\n        elif "random" == self._hpo_method:\n            from flaml import RandomSearch as SearchAlgo\n        elif "optuna" == self._hpo_method:\n            if self._use_ray is not False:\n                try:\n                    from ray import __version__ as ray_version\n\n                    assert ray_version >= "1.10.0"\n                    if ray_version.startswith("1."):\n                        from ray.tune.suggest.optuna import OptunaSearch as SearchAlgo\n                    else:\n                        from ray.tune.search.optuna import OptunaSearch as SearchAlgo\n                except (ImportError, AssertionError):\n                    from flaml.tune.searcher.suggestion import (\n                        OptunaSearch as SearchAlgo,\n                    )\n            else:\n                from flaml.tune.searcher.suggestion import OptunaSearch as SearchAlgo\n        else:\n            raise NotImplementedError(\n                f"hpo_method={self._hpo_method} is not recognized. " "\'auto\', \'cfo\' and \'bs\' are supported."\n            )\n        space = self.search_space\n        self._state.time_from_start = time.time() - self._start_time_flag\n        time_budget_s = self._state.time_budget - self._state.time_from_start if self._state.time_budget >= 0 else None\n        if self._hpo_method != "optuna":\n            min_resource = self.min_resource\n            if isinstance(min_resource, dict):\n                _min_resource_set = set(min_resource.values())\n                min_resource_all_estimator = min(_min_resource_set)\n                if len(_min_resource_set) > 1:\n                    logger.warning(\n                        "Using the min FLAML_sample_size of all the provided starting points as the starting sample size in the case of parallel search."\n                    )\n            else:\n                min_resource_all_estimator = min_resource\n            search_alg = SearchAlgo(\n                metric="val_loss",\n                space=space,\n                low_cost_partial_config=self.low_cost_partial_config,\n                points_to_evaluate=self.points_to_evaluate,\n                cat_hp_cost=self.cat_hp_cost,\n                resource_attr=self.resource_attr,\n                min_resource=min_resource_all_estimator,\n                max_resource=self.max_resource,\n                config_constraints=[(partial(size, self._state.learner_classes), "<=", self._mem_thres)],\n                metric_constraints=self.metric_constraints,\n                seed=self._seed,\n                time_budget_s=time_budget_s,\n                num_samples=self._max_iter,\n                allow_empty_config=True,\n            )\n        else:\n            # if self._hpo_method is optuna, sometimes the search space and the initial config dimension do not match\n            # need to remove the extra keys from the search space to be consistent with the initial config\n            converted_space = SearchAlgo.convert_search_space(space)\n\n            removed_keys = set(space.keys()).difference(converted_space.keys())\n            new_points_to_evaluate = []\n            for idx in range(len(self.points_to_evaluate)):\n                r = self.points_to_evaluate[idx].copy()\n                for each_key in removed_keys:\n                    r.pop(each_key)\n                new_points_to_evaluate.append(r)\n\n            search_alg = SearchAlgo(\n                metric="val_loss",\n                mode="min",\n                points_to_evaluate=[p for p in new_points_to_evaluate if len(p) == len(converted_space)],\n            )\n        search_alg = ConcurrencyLimiter(search_alg, self._n_concurrent_trials)\n        resources_per_trial = self._state.resources_per_trial\n\n        if self._use_spark:\n            # use spark as parallel backend\n            mlflow_log_latency = (\n                get_mlflow_log_latency(model_history=self._state.model_history) if self.mlflow_integration else 0\n            )\n            (\n                logger.info(f"Estimated mlflow_log_latency: {mlflow_log_latency} seconds.")\n                if mlflow_log_latency > 0\n                else None\n            )\n            analysis = tune.run(\n                self.trainable,\n                search_alg=search_alg,\n                config=space,\n                metric="val_loss",\n                mode="min",\n                time_budget_s=time_budget_s,\n                num_samples=self._max_iter,\n                verbose=max(self.verbose - 2, 0),\n                use_ray=False,\n                use_spark=True,\n                force_cancel=self._force_cancel,\n                mlflow_exp_name=self._mlflow_exp_name,\n                automl_info=(mlflow_log_latency, self._log_type),  # pass automl info to tune.run\n                extra_tag=self.autolog_extra_tag,\n                # raise_on_failed_trial=False,\n                # keep_checkpoints_num=1,\n                # checkpoint_score_attr="min-val_loss",\n            )\n        else:\n            # use ray as parallel backend\n            analysis = ray.tune.run(\n                self.trainable,\n                search_alg=search_alg,\n                config=space,\n                metric="val_loss",\n                mode="min",\n                resources_per_trial=resources_per_trial,\n                time_budget_s=time_budget_s,\n                num_samples=self._max_iter,\n                verbose=max(self.verbose - 2, 0),\n                raise_on_failed_trial=False,\n                keep_checkpoints_num=1,\n                checkpoint_score_attr="min-val_loss",\n                **self._use_ray if isinstance(self._use_ray, dict) else {},\n            )\n        # logger.info([trial.last_result for trial in analysis.trials])\n        trials = sorted(\n            (\n                trial\n                for trial in analysis.trials\n                if trial.last_result and trial.last_result.get("wall_clock_time") is not None\n            ),\n            key=lambda x: x.last_result["wall_clock_time"],\n        )\n        for self._track_iter, trial in enumerate(trials):\n            result = trial.last_result\n            better = False\n            if result:\n                config = result["config"]\n                estimator = config.get("ml", config)["learner"]\n                search_state = self._search_states[estimator]\n                search_state.update(result, 0)\n                wall_time = result.get("wall_clock_time")\n                if wall_time is not None:\n                    self._state.time_from_start = wall_time\n                self._iter_per_learner[estimator] += 1\n                if search_state.sample_size == self._state.data_size[0]:\n                    if not self._fullsize_reached:\n                        self._fullsize_reached = True\n                if search_state.best_loss < self._state.best_loss:\n                    self._state.best_loss = search_state.best_loss\n                    self._best_estimator = estimator\n                    self._config_history[self._track_iter] = (\n                        self._best_estimator,\n                        config,\n                        self._time_taken_best_iter,\n                    )\n                    self._trained_estimator = search_state.trained_estimator\n                    self._best_iteration = self._track_iter\n                    self._time_taken_best_iter = self._state.time_from_start\n                    better = True\n                    self._search_states[estimator].best_config = config\n                if better or self._log_type == "all":\n                    self._log_trial(search_state, estimator)\n                if self.mlflow_integration:\n                    self.mlflow_integration.record_state(\n                        self, search_state, estimator, better or self._log_type == "all"\n                    )\n\n    def _log_trial(self, search_state, estimator):\n        if self._training_log:\n            self._training_log.append(\n                self._iter_per_learner[estimator],\n                search_state.metric_for_logging,\n                search_state.trial_time,\n                self._state.time_from_start,\n                search_state.val_loss,\n                search_state.config,\n                estimator,\n                search_state.sample_size,\n            )\n\n    def _search_sequential(self):\n        try:\n            from ray import __version__ as ray_version\n\n            assert ray_version >= "1.10.0"\n            if ray_version.startswith("1."):\n                from ray.tune.suggest import ConcurrencyLimiter\n            else:\n                from ray.tune.search import ConcurrencyLimiter\n        except (ImportError, AssertionError):\n            from flaml.tune.searcher.suggestion import ConcurrencyLimiter\n        if self._hpo_method in ("cfo", "grid"):\n            from flaml import CFO as SearchAlgo\n        elif "optuna" == self._hpo_method:\n            try:\n                from ray import __version__ as ray_version\n\n                assert ray_version >= "1.10.0"\n                if ray_version.startswith("1."):\n                    from ray.tune.suggest.optuna import OptunaSearch as SearchAlgo\n                else:\n                    from ray.tune.search.optuna import OptunaSearch as SearchAlgo\n            except (ImportError, AssertionError):\n                from flaml.tune.searcher.suggestion import OptunaSearch as SearchAlgo\n        elif "bs" == self._hpo_method:\n            from flaml import BlendSearch as SearchAlgo\n        elif "random" == self._hpo_method:\n            from flaml.tune.searcher import RandomSearch as SearchAlgo\n        elif "cfocat" == self._hpo_method:\n            from flaml.tune.searcher.cfo_cat import CFOCat as SearchAlgo\n        else:\n            raise NotImplementedError(\n                f"hpo_method={self._hpo_method} is not recognized. " "\'cfo\' and \'bs\' are supported."\n            )\n\n        est_retrain_time = next_trial_time = 0\n        best_config_sig = None\n        better = True  # whether we find a better model in one trial\n        for self._track_iter in range(self._max_iter):\n            if self._estimator_index is None:\n                estimator = self._active_estimators[0]\n            else:\n                estimator = self._select_estimator(self._active_estimators)\n                if not estimator:\n                    break\n            logger.info(f"iteration {self._track_iter}, current learner {estimator}")\n            search_state = self._search_states[estimator]\n            self._state.time_from_start = time.time() - self._start_time_flag\n            time_left = self._state.time_budget - self._state.time_from_start\n            budget_left = (\n                time_left\n                if not self._retrain_in_budget\n                or better\n                or (not self.best_estimator)\n                or self._search_states[self.best_estimator].sample_size < self._state.data_size[0]\n                else time_left - est_retrain_time\n            )\n            if not search_state.search_alg:\n                search_state.training_function = partial(\n                    AutoMLState._compute_with_config_base,\n                    state=self._state,\n                    estimator=estimator,\n                )\n                search_space = search_state.search_space\n                if self._sample:\n                    resource_attr = "FLAML_sample_size"\n                    min_resource = (\n                        self._min_sample_size[estimator]\n                        if isinstance(self._min_sample_size, dict) and estimator in self._min_sample_size\n                        else self._min_sample_size_input\n                    )\n                    max_resource = self._state.data_size[0]\n                else:\n                    resource_attr = min_resource = max_resource = None\n                learner_class = self._state.learner_classes.get(estimator)\n                if "grid" == self._hpo_method:  # for synthetic exp only\n                    points_to_evaluate = []\n                    space = search_space\n                    keys = list(space.keys())\n                    domain0, domain1 = space[keys[0]], space[keys[1]]\n                    for x1 in range(domain0.lower, domain0.upper + 1):\n                        for x2 in range(domain1.lower, domain1.upper + 1):\n                            points_to_evaluate.append(\n                                {\n                                    keys[0]: x1,\n                                    keys[1]: x2,\n                                }\n                            )\n                    self._max_iter_per_learner = len(points_to_evaluate)\n                    low_cost_partial_config = None\n                else:\n                    points_to_evaluate = search_state.init_config.copy()\n\n                    low_cost_partial_config = search_state.low_cost_partial_config\n                time_budget_s = (\n                    min(budget_left, self._state.train_time_limit or np.inf) if self._state.time_budget >= 0 else None\n                )\n                if self._hpo_method in ("bs", "cfo", "grid", "cfocat", "random"):\n                    algo = SearchAlgo(\n                        metric="val_loss",\n                        mode="min",\n                        space=search_space,\n                        points_to_evaluate=points_to_evaluate,\n                        low_cost_partial_config=low_cost_partial_config,\n                        cat_hp_cost=search_state.cat_hp_cost,\n                        resource_attr=resource_attr,\n                        min_resource=min_resource,\n                        max_resource=max_resource,\n                        config_constraints=[(learner_class.size, "<=", self._mem_thres)],\n                        metric_constraints=self.metric_constraints,\n                        seed=self._seed,\n                        allow_empty_config=True,\n                        time_budget_s=time_budget_s,\n                        num_samples=self._max_iter,\n                    )\n                else:\n                    # if self._hpo_method is optuna, sometimes the search space and the initial config dimension do not match\n                    # need to remove the extra keys from the search space to be consistent with the initial config\n                    converted_space = SearchAlgo.convert_search_space(search_space)\n                    removed_keys = set(search_space.keys()).difference(converted_space.keys())\n                    new_points_to_evaluate = []\n                    for idx in range(len(points_to_evaluate)):\n                        r = points_to_evaluate[idx].copy()\n                        for each_key in removed_keys:\n                            r.pop(each_key)\n                        new_points_to_evaluate.append(r)\n                    points_to_evaluate = new_points_to_evaluate\n\n                    algo = SearchAlgo(\n                        metric="val_loss",\n                        mode="min",\n                        space=search_space,\n                        points_to_evaluate=[p for p in points_to_evaluate if len(p) == len(search_space)],\n                    )\n                search_state.search_alg = ConcurrencyLimiter(algo, max_concurrent=1)\n                # search_state.search_alg = algo\n            else:\n                search_space = None\n                if self._hpo_method in ("bs", "cfo", "cfocat"):\n                    search_state.search_alg.searcher.set_search_properties(\n                        metric=None,\n                        mode=None,\n                        metric_target=self._state.best_loss,\n                    )\n            start_run_time = time.time()\n            analysis = tune.run(\n                search_state.training_function,\n                search_alg=search_state.search_alg,\n                time_budget_s=time_budget_s,\n                verbose=max(self.verbose - 3, 0),\n                use_ray=False,\n                use_spark=False,\n                force_cancel=self._force_cancel,\n                mlflow_exp_name=self._mlflow_exp_name,\n                automl_info=(0,),  # pass automl info to tune.run\n                extra_tag=self.autolog_extra_tag,\n            )\n            time_used = time.time() - start_run_time\n            better = False\n            (\n                logger.debug(f"result in automl: {analysis.trials}, {analysis.trials[-1].last_result}")\n                if analysis.trials\n                else logger.debug("result in automl: [], None")\n            )\n            if analysis.trials and analysis.trials[-1].last_result:\n                result = analysis.trials[-1].last_result\n                search_state.update(result, time_used=time_used)\n                if self._estimator_index is None:\n                    # update init eci estimate\n                    eci_base = search_state.init_eci\n                    self._eci.append(search_state.estimated_cost4improvement)\n                    for e in self.estimator_list[1:]:\n                        self._eci.append(self._search_states[e].init_eci / eci_base * self._eci[0])\n                    self._estimator_index = 0\n                    min_budget = max(10 * self._eci[0], sum(self._eci))\n                    max_budget = 10000 * self._eci[0]\n                    if search_state.sample_size:\n                        ratio = search_state.data_size[0] / search_state.sample_size\n                        min_budget *= ratio\n                        max_budget *= ratio\n                    logger.info(\n                        f"Estimated sufficient time budget={max_budget:.0f}s."\n                        f" Estimated necessary time budget={min_budget:.0f}s."\n                    )\n                wall_time = result.get("wall_clock_time")\n                if wall_time is not None:\n                    self._state.time_from_start = wall_time\n                # logger.info(f"{self._search_states[estimator].sample_size}, {data_size}")\n                if search_state.sample_size == self._state.data_size[0]:\n                    self._iter_per_learner_fullsize[estimator] += 1\n                    self._fullsize_reached = True\n                self._iter_per_learner[estimator] += 1\n                if search_state.best_loss < self._state.best_loss:\n                    best_config_sig = estimator + search_state.get_hist_config_sig(\n                        self.data_size_full, search_state.best_config\n                    )\n                    self._state.best_loss = search_state.best_loss\n                    self._best_estimator = estimator\n                    est_retrain_time = (\n                        search_state.est_retrain_time(self.data_size_full)\n                        if (best_config_sig not in self._retrained_config)\n                        else 0\n                    )\n                    self._config_history[self._track_iter] = (\n                        estimator,\n                        search_state.best_config,\n                        self._state.time_from_start,\n                    )\n                    if self._trained_estimator:\n                        self._trained_estimator.cleanup()\n                        del self._trained_estimator\n                        self._trained_estimator = None\n                    if not self._state.retrain_final:\n                        self._trained_estimator = search_state.trained_estimator\n                    self._best_iteration = self._track_iter\n                    self._time_taken_best_iter = self._state.time_from_start\n                    better = True\n                    next_trial_time = search_state.time2eval_best\n                if (\n                    search_state.trained_estimator\n                    and not self._state.model_history\n                    and search_state.trained_estimator != self._trained_estimator\n                ):\n                    search_state.trained_estimator.cleanup()\n                if better or self._log_type == "all":\n                    self._log_trial(search_state, estimator)\n                if self.mlflow_integration:\n                    self.mlflow_integration.record_state(\n                        self, search_state, estimator, better or self._log_type == "all"\n                    )\n\n                logger.info(\n                    " at {:.1f}s,\\testimator {}\'s best error={:.4f},\\tbest estimator {}\'s best error={:.4f}".format(\n                        self._state.time_from_start,\n                        estimator,\n                        search_state.best_loss,\n                        self._best_estimator,\n                        self._state.best_loss,\n                    )\n                )\n                if (\n                    self._hpo_method in ("cfo", "bs")\n                    and all(\n                        state.search_alg and state.search_alg.searcher.is_ls_ever_converged\n                        for state in self._search_states.values()\n                    )\n                    and (self._state.time_from_start > self._warn_threshold * self._time_taken_best_iter)\n                ):\n                    logger.warning(\n                        "All estimator hyperparameters local search has "\n                        "converged at least once, and the total search time "\n                        f"exceeds {self._warn_threshold} times the time taken "\n                        "to find the best model."\n                    )\n                    if self._early_stop:\n                        logger.warning("Stopping search as early_stop is set to True.")\n                        break\n                    self._warn_threshold *= 10\n            else:\n                logger.info(f"stop trying learner {estimator}")\n                if self._estimator_index is not None:\n                    self._active_estimators.remove(estimator)\n                    self._estimator_index -= 1\n                search_state.search_alg.searcher._is_ls_ever_converged = True\n            if (\n                self._retrain_in_budget\n                and best_config_sig\n                and est_retrain_time\n                and not better\n                and self._search_states[self._best_estimator].sample_size == self._state.data_size[0]\n                and (\n                    est_retrain_time\n                    <= self._state.time_budget - self._state.time_from_start\n                    <= est_retrain_time + next_trial_time\n                )\n            ):\n                state = self._search_states[self._best_estimator]\n                self._trained_estimator, retrain_time = self._state._train_with_config(\n                    self._best_estimator,\n                    state.best_config,\n                    self.data_size_full,\n                )\n                logger.info(f"retrain {self._best_estimator} for {retrain_time:.1f}s")\n                self._retrained_config[best_config_sig] = state.best_config_train_time = retrain_time\n                est_retrain_time = 0\n            self._state.time_from_start = time.time() - self._start_time_flag\n            if self._state.time_from_start >= self._state.time_budget >= 0 or not self._active_estimators:\n                break\n            if self._ensemble and self._best_estimator:\n                time_left = self._state.time_budget - self._state.time_from_start\n                time_ensemble = self._search_states[self._best_estimator].time2eval_best\n                if time_left < time_ensemble < 2 * time_left:\n                    break\n\n    def _search(self):\n        # initialize the search_states\n        self._eci = []\n        self._state.best_loss = float("+inf")\n        self._state.time_from_start = 0\n        self._estimator_index = None\n        self._best_iteration = 0\n        self._time_taken_best_iter = 0\n        self._config_history = {}\n        self._max_iter_per_learner = 10000\n        self._iter_per_learner = {e: 0 for e in self.estimator_list}\n        self._iter_per_learner_fullsize = {e: 0 for e in self.estimator_list}\n        self._fullsize_reached = False\n        self._trained_estimator = None\n        self._best_estimator = None\n        self._retrained_config = {}\n        self._warn_threshold = 10\n        self._selected = None\n        self.modelcount = 0\n        if self._max_iter < 2 and self.estimator_list and self._state.retrain_final:\n            # when max_iter is 1, no need to search\n            self.modelcount = self._max_iter\n            self._max_iter = 0\n            self._best_estimator = estimator = self.estimator_list[0]\n            self._selected = state = self._search_states[estimator]\n            state.best_config_sample_size = self._state.data_size[0]\n            state.best_config = state.init_config[0] if state.init_config else {}\n            self._track_iter = 0\n            self._config_history[self._track_iter] = (estimator, state.best_config, self._state.time_from_start)\n            self._best_iteration = self._track_iter\n            state.val_loss = getattr(state, "val_loss", float("inf"))\n            state.best_loss = getattr(state, "best_loss", float("inf"))\n            state.config = getattr(state, "config", state.best_config.copy())\n            state.metric_for_logging = getattr(state, "metric_for_logging", None)\n            state.sample_size = getattr(state, "sample_size", self._state.data_size[0])\n            state.learner_class = getattr(state, "learner_class", self._state.learner_classes.get(estimator))\n            if hasattr(self, "mlflow_integration") and self.mlflow_integration:\n                self.mlflow_integration.record_state(\n                    automl=self,\n                    search_state=state,\n                    estimator=estimator,\n                )\n        elif self._use_ray is False and self._use_spark is False:\n            self._search_sequential()\n        else:\n            self._search_parallel()\n        # Add a checkpoint for the current best config to the log.\n        if self._training_log:\n            self._training_log.checkpoint()\n        self._state.time_from_start = time.time() - self._start_time_flag\n        if self._best_estimator:\n            if self.mlflow_integration:\n                self.mlflow_integration.log_automl(self)\n                if mlflow.active_run() is None:\n                    if self.mlflow_integration.parent_run_id is not None and self.mlflow_integration.autolog:\n                        # ensure result of retrain autolog to parent run\n                        mlflow.start_run(run_id=self.mlflow_integration.parent_run_id)\n            self._selected = self._search_states[self._best_estimator]\n            self.modelcount = sum(search_state.total_iter for search_state in self._search_states.values())\n            if self._trained_estimator:\n                logger.info(f"selected model: {self._trained_estimator.model}")\n            estimators = []\n            if self._ensemble and self._state.task in (\n                "binary",\n                "multiclass",\n                "regression",\n            ):\n                search_states = list(x for x in self._search_states.items() if x[1].best_config)\n                search_states.sort(key=lambda x: x[1].best_loss)\n                estimators = [\n                    (\n                        x[0],\n                        x[1].learner_class(\n                            task=self._state.task,\n                            n_jobs=self._state.n_jobs,\n                            **AutoMLState.sanitize(x[1].best_config),\n                        ),\n                    )\n                    for x in search_states[:2]\n                ]\n                estimators += [\n                    (\n                        x[0],\n                        x[1].learner_class(\n                            task=self._state.task,\n                            n_jobs=self._state.n_jobs,\n                            **AutoMLState.sanitize(x[1].best_config),\n                        ),\n                    )\n                    for x in search_states[2:]\n                    if x[1].best_loss < 4 * self._selected.best_loss\n                ]\n                logger.info([(estimator[0], estimator[1].params) for estimator in estimators])\n            if len(estimators) > 1:\n                if self._state.task.is_classification():\n                    from sklearn.ensemble import StackingClassifier as Stacker\n                else:\n                    from sklearn.ensemble import StackingRegressor as Stacker\n                if self._use_ray is not False:\n                    import ray\n\n                    n_cpus = ray.is_initialized() and ray.available_resources()["CPU"] or os.cpu_count()\n                elif self._use_spark:\n                    from flaml.tune.spark.utils import get_n_cpus\n\n                    n_cpus = get_n_cpus()\n                else:\n                    n_cpus = os.cpu_count()\n                ensemble_n_jobs = (\n                    -self._state.n_jobs  # maximize total parallelization degree\n                    if abs(self._state.n_jobs) == 1  # 1 and -1 correspond to min/max parallelization\n                    else max(1, int(n_cpus / 2 / self._state.n_jobs))\n                    # the total degree of parallelization = parallelization degree per estimator * parallelization degree of ensemble\n                )\n                if isinstance(self._ensemble, dict):\n                    final_estimator = self._ensemble.get("final_estimator", self._trained_estimator)\n                    passthrough = self._ensemble.get("passthrough", True)\n                    ensemble_n_jobs = self._ensemble.get("n_jobs", ensemble_n_jobs)\n                else:\n                    final_estimator = self._trained_estimator\n                    passthrough = True\n                stacker = Stacker(\n                    estimators,\n                    final_estimator,\n                    n_jobs=ensemble_n_jobs,\n                    passthrough=passthrough,\n                )\n                sample_weight_dict = (\n                    (self._sample_weight_full is not None) and {"sample_weight": self._sample_weight_full} or {}\n                )\n                for e in estimators:\n                    e[1].__class__.init()\n                import joblib\n\n                try:\n                    logger.info("Building ensemble with tuned estimators")\n                    stacker.fit(\n                        self._X_train_all,\n                        self._y_train_all,\n                        **sample_weight_dict,  # NOTE: _search is after kwargs is updated to fit_kwargs_by_estimator\n                    )\n                    logger.info(f"ensemble: {stacker}")\n                    self._trained_estimator = stacker\n                    self._trained_estimator.model = stacker\n                except ValueError as e:\n                    if passthrough:\n                        logger.warning(\n                            "Using passthrough=False for ensemble because the data contain categorical features."\n                        )\n                        stacker = Stacker(\n                            estimators,\n                            final_estimator,\n                            n_jobs=self._state.n_jobs,\n                            passthrough=False,\n                        )\n                        stacker.fit(\n                            self._X_train_all,\n                            self._y_train_all,\n                            **sample_weight_dict,  # NOTE: _search is after kwargs is updated to fit_kwargs_by_estimator\n                        )\n                        logger.info(f"ensemble: {stacker}")\n                        self._trained_estimator = stacker\n                        self._trained_estimator.model = stacker\n                    else:\n                        raise e\n                except joblib.externals.loky.process_executor.TerminatedWorkerError:\n                    logger.error(\n                        "No enough memory to build the ensemble."\n                        " Please try increasing available RAM, decreasing n_jobs for ensemble, or disabling ensemble."\n                    )\n            elif self._state.retrain_final:\n                # reset time budget for retraining\n                if self._max_iter > 1:\n                    self._state.time_budget = -1\n                if (\n                    self._state.task.is_ts_forecast()\n                    or self._trained_estimator is None\n                    or self._trained_estimator.model is None\n                    or (\n                        self._state.time_budget < 0\n                        or self._state.time_budget - self._state.time_from_start\n                        > self._selected.est_retrain_time(self.data_size_full)\n                    )\n                    and self._selected.best_config_sample_size == self._state.data_size[0]\n                ):\n                    state = self._search_states[self._best_estimator]\n                    (\n                        self._trained_estimator,\n                        retrain_time,\n                    ) = self._state._train_with_config(\n                        self._best_estimator,\n                        state.best_config,\n                        self.data_size_full,\n                        is_retrain=True,\n                    )\n                    logger.info(f"retrain {self._best_estimator} for {retrain_time:.1f}s")\n                    state.best_config_train_time = retrain_time\n                    if self._trained_estimator:\n                        logger.info(f"retrained model: {self._trained_estimator.model}")\n                        if self.best_run_id is not None:\n                            logger.info(f"Best MLflow run name: {self.best_run_name}")\n                            logger.info(f"Best MLflow run id: {self.best_run_id}")\n                        if self.mlflow_integration is not None:\n                            # try log retrained model\n                            if all(\n                                [\n                                    self.mlflow_integration.manual_log,\n                                    not self.mlflow_integration.has_model,\n                                    self.mlflow_integration.parent_run_id is not None,\n                                ]\n                            ):\n                                if mlflow.active_run() is None:\n                                    mlflow.start_run(run_id=self.mlflow_integration.parent_run_id)\n                                if self.best_estimator.endswith("_spark"):\n                                    self.mlflow_integration.log_model(\n                                        self._trained_estimator.model,\n                                        self.best_estimator,\n                                        signature=self.estimator_signature,\n                                        run_id=self.mlflow_integration.parent_run_id,\n                                    )\n                                else:\n                                    self.mlflow_integration.pickle_and_log_automl_artifacts(\n                                        self,\n                                        self.model,\n                                        self.best_estimator,\n                                        signature=self.pipeline_signature,\n                                        run_id=self.mlflow_integration.parent_run_id,\n                                    )\n                else:\n                    logger.warning("not retraining because the time budget is too small.")\n        self.wait_futures()\n\n    def wait_futures(self):\n        if self.mlflow_integration is not None:\n            logger.debug("Collecting results from submitted record_state tasks")\n            t1 = time.perf_counter()\n            for future in as_completed(self.mlflow_integration.futures):\n                _task = self.mlflow_integration.futures[future]\n                try:\n                    result = future.result()\n                    logger.debug(f"Result for record_state task {_task}: {result}")\n                except Exception as e:\n                    logger.warning(f"Exception for record_state task {_task}: {e}")\n            for future in as_completed(self.mlflow_integration.futures_log_model):\n                _task = self.mlflow_integration.futures_log_model[future]\n                try:\n                    result = future.result()\n                    logger.debug(f"Result for log_model task {_task}: {result}")\n                except Exception as e:\n                    logger.warning(f"Exception for log_model task {_task}: {e}")\n            t2 = time.perf_counter()\n            logger.debug(f"Collecting results from tasks submitted to executors costs {t2-t1} seconds.")\n        else:\n            logger.debug("No futures to wait for.")\n\n    def __del__(self):\n        if (\n            hasattr(self, "_trained_estimator")\n            and self._trained_estimator\n            and hasattr(self._trained_estimator, "cleanup")\n        ):\n            if self.preserve_checkpoint is False:\n                self._trained_estimator.cleanup()\n            del self._trained_estimator\n\n    def _select_estimator(self, estimator_list):\n        if self._learner_selector == "roundrobin":\n            self._estimator_index += 1\n            if self._estimator_index == len(estimator_list):\n                self._estimator_index = 0\n            return estimator_list[self._estimator_index]\n        min_estimated_cost, selected = np.inf, None\n        inv = []\n        untried_exists = False\n        for i, estimator in enumerate(estimator_list):\n            if estimator in self._search_states and (\n                self._search_states[estimator].sample_size\n            ):  # sample_size=None meaning no result\n                search_state = self._search_states[estimator]\n                if (\n                    self._state.time_budget >= 0\n                    and self._search_states[estimator].time2eval_best\n                    > self._state.time_budget - self._state.time_from_start\n                    or self._iter_per_learner_fullsize[estimator] >= self._max_iter_per_learner\n                ):\n                    inv.append(0)\n                    continue\n                estimated_cost = search_state.estimated_cost4improvement\n                if search_state.sample_size < self._state.data_size[0] and self._state.time_budget >= 0:\n                    estimated_cost = min(\n                        estimated_cost,\n                        search_state.time2eval_best\n                        * min(\n                            SAMPLE_MULTIPLY_FACTOR,\n                            self._state.data_size[0] / search_state.sample_size,\n                        ),\n                    )\n                gap = search_state.best_loss - self._state.best_loss\n                if gap > 0 and not self._ensemble:\n                    delta_loss = (search_state.best_loss_old - search_state.best_loss) or search_state.best_loss\n                    delta_time = (search_state.total_time_used - search_state.time_best_found_old) or 1e-10\n                    speed = delta_loss / delta_time\n                    if speed:\n                        estimated_cost = max(2 * gap / speed, estimated_cost)\n                estimated_cost = estimated_cost or 1e-9\n                inv.append(1 / estimated_cost)\n            else:\n                estimated_cost = self._eci[i]\n                inv.append(0)\n                untried_exists = True\n            if estimated_cost < min_estimated_cost:\n                min_estimated_cost = estimated_cost\n                selected = estimator\n        if untried_exists or not selected:\n            state = self._search_states.get(selected)\n            if not (state and state.sample_size):\n                return selected\n        s = sum(inv)\n        p = self._random.rand()\n        q = 0\n        for i in range(len(inv)):\n            if inv[i]:\n                q += inv[i] / s\n                if p < q:\n                    return estimator_list[i]\n\n    @property\n    def automl_pipeline(self):\n        return None\n',
            'test/automl/test_multiclass.py': 'import unittest\n\nimport numpy as np\nimport scipy.sparse\nfrom sklearn.datasets import load_iris, load_wine\n\nfrom flaml import AutoML, tune\nfrom flaml.automl.data import get_output_from_log\nfrom flaml.automl.model import LGBMEstimator, SKLearnEstimator, XGBoostSklearnEstimator\nfrom flaml.automl.training_log import training_log_reader\n\n\nclass MyRegularizedGreedyForest(SKLearnEstimator):\n    def __init__(self, task="binary", **config):\n        super().__init__(task, **config)\n\n        if isinstance(task, str):\n            from flaml.automl.task.factory import task_factory\n\n            task = task_factory(task)\n\n        if task.is_classification():\n            from rgf.sklearn import RGFClassifier\n\n            self.estimator_class = RGFClassifier\n        else:\n            from rgf.sklearn import RGFRegressor\n\n            self.estimator_class = RGFRegressor\n\n    @classmethod\n    def search_space(cls, data_size, task):\n        space = {\n            "max_leaf": {\n                "domain": tune.lograndint(lower=4, upper=data_size[0]),\n                "init_value": 4,\n            },\n            "n_iter": {\n                "domain": tune.lograndint(lower=1, upper=data_size[0]),\n                "init_value": 1,\n            },\n            "n_tree_search": {\n                "domain": tune.lograndint(lower=1, upper=32768),\n                "init_value": 1,\n            },\n            "opt_interval": {\n                "domain": tune.lograndint(lower=1, upper=10000),\n                "init_value": 100,\n            },\n            "learning_rate": {"domain": tune.loguniform(lower=0.01, upper=20.0)},\n            "min_samples_leaf": {\n                "domain": tune.lograndint(lower=1, upper=20),\n                "init_value": 20,\n            },\n        }\n        return space\n\n    @classmethod\n    def size(cls, config):\n        max_leaves = int(round(config.get("max_leaf", 1)))\n        n_estimators = int(round(config.get("n_iter", 1)))\n        return (max_leaves * 3 + (max_leaves - 1) * 4 + 1.0) * n_estimators * 8\n\n    @classmethod\n    def cost_relative2lgbm(cls):\n        return 1.0\n\n\nclass MyLargeXGB(XGBoostSklearnEstimator):\n    @classmethod\n    def search_space(cls, **params):\n        return {\n            "n_estimators": {\n                "domain": tune.lograndint(lower=4, upper=32768),\n                "init_value": 32768,\n                "low_cost_init_value": 4,\n            },\n            "max_leaves": {\n                "domain": tune.lograndint(lower=4, upper=3276),\n                "init_value": 3276,\n                "low_cost_init_value": 4,\n            },\n        }\n\n\nclass MyLargeLGBM(LGBMEstimator):\n    @classmethod\n    def search_space(cls, **params):\n        return {\n            "n_estimators": {\n                "domain": tune.lograndint(lower=4, upper=32768),\n                "init_value": 32768,\n                "low_cost_init_value": 4,\n            },\n            "num_leaves": {\n                "domain": tune.lograndint(lower=4, upper=3276),\n                "init_value": 3276,\n                "low_cost_init_value": 4,\n            },\n        }\n\n\ndef custom_metric(\n    X_val,\n    y_val,\n    estimator,\n    labels,\n    X_train,\n    y_train,\n    weight_val=None,\n    weight_train=None,\n    config=None,\n    groups_val=None,\n    groups_train=None,\n):\n    import time\n\n    from sklearn.metrics import log_loss\n\n    start = time.time()\n    y_pred = estimator.predict_proba(X_val)\n    pred_time = (time.time() - start) / len(X_val)\n    val_loss = log_loss(y_val, y_pred, labels=labels, sample_weight=weight_val)\n    y_pred = estimator.predict_proba(X_train)\n    train_loss = log_loss(y_train, y_pred, labels=labels, sample_weight=weight_train)\n    alpha = 0.5\n    return val_loss * (1 + alpha) - alpha * train_loss, {\n        "val_loss": val_loss,\n        "train_loss": train_loss,\n        "pred_time": pred_time,\n    }\n\n\nclass TestMultiClass(unittest.TestCase):\n    def test_custom_learner(self):\n        automl = AutoML()\n        automl.add_learner(learner_name="RGF", learner_class=MyRegularizedGreedyForest)\n        X_train, y_train = load_wine(return_X_y=True)\n        settings = {\n            "time_budget": 8,  # total running time in seconds\n            "estimator_list": ["RGF", "lgbm", "rf", "xgboost"],\n            "task": "classification",  # task type\n            "sample": True,  # whether to subsample training data\n            "log_file_name": "test/wine.log",\n            "log_training_metric": True,  # whether to log training metric\n            "n_jobs": 1,\n        }\n        automl.fit(X_train=X_train, y_train=y_train, **settings)\n        # print the best model found for RGF\n        print(automl.best_model_for_estimator("RGF"))\n\n        MyRegularizedGreedyForest.search_space = lambda data_size, task: {}\n        automl.fit(X_train=X_train, y_train=y_train, **settings)\n\n        try:\n            import ray\n\n            del settings["time_budget"]\n            settings["max_iter"] = 5\n            # test the "_choice_" issue when using ray\n            automl.fit(X_train=X_train, y_train=y_train, n_concurrent_trials=2, **settings)\n        except ImportError:\n            return\n\n    def test_ensemble(self):\n        automl = AutoML()\n        automl.add_learner(learner_name="RGF", learner_class=MyRegularizedGreedyForest)\n        X_train, y_train = load_wine(return_X_y=True)\n        settings = {\n            "time_budget": 5,  # total running time in seconds\n            "estimator_list": ["rf", "xgboost", "catboost"],\n            "task": "classification",  # task type\n            "sample": True,  # whether to subsample training data\n            "log_file_name": "test/wine.log",\n            "log_training_metric": True,  # whether to log training metric\n            "ensemble": {\n                "final_estimator": MyRegularizedGreedyForest(),\n                "passthrough": False,\n            },\n            "n_jobs": 1,\n        }\n        automl.fit(X_train=X_train, y_train=y_train, **settings)\n\n    def test_dataframe(self):\n        self.test_classification(True)\n\n    def test_custom_metric(self):\n        df, y = load_iris(return_X_y=True, as_frame=True)\n        df["label"] = y\n        settings = {\n            "dataframe": df,\n            "label": "label",\n            "time_budget": 5,\n            "eval_method": "cv",\n            "metric": custom_metric,\n            "task": "classification",\n            "log_file_name": "test/iris_custom.log",\n            "log_training_metric": True,\n            "log_type": "all",\n            "n_jobs": 1,\n            "model_history": True,\n            "sample_weight": np.ones(len(y)),\n            "pred_time_limit": 1e-5,\n            "ensemble": True,\n        }\n        automl = AutoML(**settings)  # test safe_json_dumps\n        automl.fit(dataframe=df, label="label")\n        print(automl.classes_)\n        print(automl.model)\n        print(automl.config_history)\n        print(automl.best_model_for_estimator("rf"))\n        print(automl.best_iteration)\n        print(automl.best_estimator)\n        automl = AutoML()\n        estimator = automl.get_estimator_from_log(settings["log_file_name"], record_id=0, task="multiclass")\n        print(estimator)\n        (\n            time_history,\n            best_valid_loss_history,\n            valid_loss_history,\n            config_history,\n            metric_history,\n        ) = get_output_from_log(filename=settings["log_file_name"], time_budget=6)\n        print(metric_history)\n        try:\n            import ray\n\n            df = ray.put(df)\n            settings["dataframe"] = df\n            settings["use_ray"] = True\n            del settings["time_budget"]\n            settings["max_iter"] = 2\n            automl.fit(**settings)\n            estimator = automl.get_estimator_from_log(settings["log_file_name"], record_id=1, task="multiclass")\n        except ImportError:\n            pass\n\n    def test_classification(self, as_frame=False):\n        automl_experiment = AutoML()\n        automl_settings = {\n            "time_budget": 4,\n            "metric": "accuracy",\n            "task": "classification",\n            "log_file_name": "test/iris.log",\n            "log_training_metric": True,\n            "n_jobs": 1,\n            "model_history": True,\n        }\n        X_train, y_train = load_iris(return_X_y=True, as_frame=as_frame)\n        if as_frame:\n            # test drop column\n            X_train.columns = range(X_train.shape[1])\n            X_train[X_train.shape[1]] = np.zeros(len(y_train))\n        automl_experiment.fit(X_train=X_train, y_train=y_train, **automl_settings)\n        print(automl_experiment.classes_)\n        print(automl_experiment.predict(X_train)[:5])\n        print(automl_experiment.model)\n        print(automl_experiment.config_history)\n        print(automl_experiment.best_model_for_estimator("catboost"))\n        print(automl_experiment.best_iteration)\n        print(automl_experiment.best_estimator)\n        del automl_settings["metric"]\n        del automl_settings["model_history"]\n        del automl_settings["log_training_metric"]\n        automl_experiment = AutoML(task="classification")\n        duration = automl_experiment.retrain_from_log(\n            log_file_name=automl_settings["log_file_name"],\n            X_train=X_train,\n            y_train=y_train,\n            train_full=True,\n            record_id=0,\n        )\n        print(duration)\n        print(automl_experiment.model)\n        print(automl_experiment.predict_proba(X_train)[:5])\n\n    def test_micro_macro_f1(self):\n        automl_experiment_micro = AutoML()\n        automl_experiment_macro = AutoML()\n        automl_settings = {\n            "time_budget": 2,\n            "task": "classification",\n            "log_file_name": "test/micro_macro_f1.log",\n            "log_training_metric": True,\n            "n_jobs": 1,\n            "model_history": True,\n        }\n        X_train, y_train = load_iris(return_X_y=True)\n        automl_experiment_micro.fit(X_train=X_train, y_train=y_train, metric="micro_f1", **automl_settings)\n        automl_experiment_macro.fit(X_train=X_train, y_train=y_train, metric="macro_f1", **automl_settings)\n        estimator = automl_experiment_macro.model\n        y_pred = estimator.predict(X_train)\n        y_pred_proba = estimator.predict_proba(X_train)\n        from flaml.automl.ml import multi_class_curves, norm_confusion_matrix\n\n        print(norm_confusion_matrix(y_train, y_pred))\n        from sklearn.metrics import precision_recall_curve, roc_curve\n\n        print(multi_class_curves(y_train, y_pred_proba, roc_curve))\n        print(multi_class_curves(y_train, y_pred_proba, precision_recall_curve))\n\n    def test_roc_auc_ovr(self):\n        automl_experiment = AutoML()\n        X_train, y_train = load_iris(return_X_y=True)\n        automl_settings = {\n            "time_budget": 1,\n            "metric": "roc_auc_ovr",\n            "task": "classification",\n            "log_file_name": "test/roc_auc_ovr.log",\n            "log_training_metric": True,\n            "n_jobs": 1,\n            "sample_weight": np.ones(len(y_train)),\n            "eval_method": "holdout",\n            "model_history": True,\n        }\n        automl_experiment.fit(X_train=X_train, y_train=y_train, **automl_settings)\n\n    def test_roc_auc_ovo(self):\n        automl_experiment = AutoML()\n        automl_settings = {\n            "time_budget": 1,\n            "metric": "roc_auc_ovo",\n            "task": "classification",\n            "log_file_name": "test/roc_auc_ovo.log",\n            "log_training_metric": True,\n            "n_jobs": 1,\n            "model_history": True,\n        }\n        X_train, y_train = load_iris(return_X_y=True)\n        automl_experiment.fit(X_train=X_train, y_train=y_train, **automl_settings)\n\n    def test_roc_auc_ovr_weighted(self):\n        automl = AutoML()\n        settings = {\n            "time_budget": 1,\n            "metric": "roc_auc_ovr_weighted",\n            "task": "classification",\n            "log_file_name": "test/roc_auc_weighted.log",\n            "log_training_metric": True,\n            "n_jobs": 1,\n            "model_history": True,\n        }\n        X_train, y_train = load_iris(return_X_y=True)\n        automl.fit(X_train=X_train, y_train=y_train, **settings)\n\n    def test_roc_auc_ovo_weighted(self):\n        automl_experiment = AutoML()\n        automl_settings = {\n            "time_budget": 1,\n            "metric": "roc_auc_ovo_weighted",\n            "task": "classification",\n            "log_file_name": "test/roc_auc_weighted.log",\n            "log_training_metric": True,\n            "n_jobs": 1,\n            "model_history": True,\n        }\n        X_train, y_train = load_iris(return_X_y=True)\n        automl_experiment.fit(X_train=X_train, y_train=y_train, **automl_settings)\n\n    def test_sparse_matrix_classification(self):\n        automl_experiment = AutoML()\n        automl_settings = {\n            "time_budget": 2,\n            "metric": "auto",\n            "task": "classification",\n            "log_file_name": "test/sparse_classification.log",\n            "split_type": "uniform",\n            "n_jobs": 1,\n            "model_history": True,\n        }\n        # NOTE: Avoid `dtype=int` here. On some NumPy/SciPy combinations (notably\n        # Windows + Python 3.13), `scipy.sparse.random(..., dtype=int)` may trigger\n        # integer sampling paths which raise "low is out of bounds for int32".\n        # A float sparse matrix is sufficient to validate sparse-input support.\n        X_train = scipy.sparse.random(1554, 21, dtype=np.float32)\n        y_train = np.random.randint(3, size=1554)\n        automl_experiment.fit(X_train=X_train, y_train=y_train, **automl_settings)\n        print(automl_experiment.classes_)\n        print(automl_experiment.predict_proba(X_train))\n        print(automl_experiment.model)\n        print(automl_experiment.config_history)\n        print(automl_experiment.best_model_for_estimator("extra_tree"))\n        print(automl_experiment.best_iteration)\n        print(automl_experiment.best_estimator)\n\n    def _test_memory_limit(self):\n        automl_experiment = AutoML()\n        automl_experiment.add_learner(learner_name="large_lgbm", learner_class=MyLargeLGBM)\n        automl_settings = {\n            "time_budget": -1,\n            "task": "classification",\n            "log_file_name": "test/classification_oom.log",\n            "estimator_list": ["large_lgbm"],\n            "log_type": "all",\n            "hpo_method": "random",\n            "free_mem_ratio": 0.2,\n        }\n        X_train, y_train = load_iris(return_X_y=True, as_frame=True)\n\n        automl_experiment.fit(X_train=X_train, y_train=y_train, max_iter=1, **automl_settings)\n        print(automl_experiment.model)\n\n    def test_time_limit(self):\n        automl_experiment = AutoML()\n        automl_experiment.add_learner(learner_name="large_lgbm", learner_class=MyLargeLGBM)\n        automl_experiment.add_learner(learner_name="large_xgb", learner_class=MyLargeXGB)\n        automl_settings = {\n            "time_budget": 0.5,\n            "task": "classification",\n            "log_file_name": "test/classification_timeout.log",\n            "estimator_list": ["catboost"],\n            "log_type": "all",\n            "hpo_method": "random",\n        }\n        X_train, y_train = load_iris(return_X_y=True, as_frame=True)\n        automl_experiment.fit(X_train=X_train, y_train=y_train, **automl_settings)\n        print(automl_experiment.model.params)\n        automl_settings["estimator_list"] = ["large_xgb"]\n        automl_experiment.fit(X_train=X_train, y_train=y_train, **automl_settings)\n        print(automl_experiment.model)\n        automl_settings["estimator_list"] = ["large_lgbm"]\n        automl_experiment.fit(X_train=X_train, y_train=y_train, **automl_settings)\n        print(automl_experiment.model)\n\n    def test_fit_w_starting_point(self, as_frame=True, n_concurrent_trials=1):\n        automl = AutoML()\n        settings = {\n            "max_iter": 3,\n            "metric": "accuracy",\n            "task": "classification",\n            "log_file_name": "test/iris.log",\n            "log_training_metric": True,\n            "n_jobs": 1,\n            "model_history": True,\n        }\n        X_train, y_train = load_iris(return_X_y=True, as_frame=as_frame)\n        if as_frame:\n            # test drop column\n            X_train.columns = range(X_train.shape[1])\n            X_train[X_train.shape[1]] = np.zeros(len(y_train))\n        automl.fit(X_train=X_train, y_train=y_train, n_concurrent_trials=n_concurrent_trials, **settings)\n        automl_val_accuracy = 1.0 - automl.best_loss\n        print("Best ML leaner:", automl.best_estimator)\n        print("Best hyperparmeter config:", automl.best_config)\n        print(f"Best accuracy on validation data: {automl_val_accuracy:.4g}")\n        print(f"Training duration of best run: {automl.best_config_train_time:.4g} s")\n\n        starting_points = automl.best_config_per_estimator\n        print("starting_points", starting_points)\n        print("loss of the starting_points", automl.best_loss_per_estimator)\n        settings_resume = {\n            "time_budget": 2,\n            "metric": "accuracy",\n            "task": "classification",\n            "log_file_name": "test/iris_resume.log",\n            "log_training_metric": True,\n            "n_jobs": 1,\n            "model_history": True,\n            "log_type": "all",\n            "starting_points": starting_points,\n        }\n        new_automl = AutoML()\n        new_automl.fit(X_train=X_train, y_train=y_train, **settings_resume)\n\n        new_automl_val_accuracy = 1.0 - new_automl.best_loss\n        print("Best ML leaner:", new_automl.best_estimator)\n        print("Best hyperparmeter config:", new_automl.best_config)\n        print(f"Best accuracy on validation data: {new_automl_val_accuracy:.4g}")\n        print(f"Training duration of best run: {new_automl.best_config_train_time:.4g} s")\n\n    def test_fit_w_starting_point_2(self, as_frame=True):\n        try:\n            import ray\n\n            self.test_fit_w_starting_points_list(as_frame, 2)\n            self.test_fit_w_starting_point(as_frame, 2)\n        except ImportError:\n            pass\n\n    def test_fit_w_starting_points_list(self, as_frame=True, n_concurrent_trials=1):\n        automl = AutoML()\n        settings = {\n            "max_iter": 3,\n            "metric": "accuracy",\n            "task": "classification",\n            "log_file_name": "test/iris.log",\n            "log_training_metric": True,\n            "n_jobs": 1,\n            "model_history": True,\n        }\n        X_train, y_train = load_iris(return_X_y=True, as_frame=as_frame)\n        if as_frame:\n            # test drop column\n            X_train.columns = range(X_train.shape[1])\n            X_train[X_train.shape[1]] = np.zeros(len(y_train))\n        automl.fit(X_train=X_train, y_train=y_train, n_concurrent_trials=n_concurrent_trials, **settings)\n        automl_val_accuracy = 1.0 - automl.best_loss\n        print("Best ML leaner:", automl.best_estimator)\n        print("Best hyperparmeter config:", automl.best_config)\n        print(f"Best accuracy on validation data: {automl_val_accuracy:.4g}")\n        print(f"Training duration of best run: {automl.best_config_train_time:.4g} s")\n\n        starting_points = {}\n        log_file_name = settings["log_file_name"]\n        with training_log_reader(log_file_name) as reader:\n            sample_size = 1000\n            for record in reader.records():\n                config = record.config\n                config["FLAML_sample_size"] = sample_size\n                sample_size += 1000\n                learner = record.learner\n                if learner not in starting_points:\n                    starting_points[learner] = []\n                starting_points[learner].append(config)\n        max_iter = sum(len(s) for k, s in starting_points.items())\n        settings_resume = {\n            "time_budget": 2,\n            "metric": "accuracy",\n            "task": "classification",\n            "log_file_name": "test/iris_resume_all.log",\n            "log_training_metric": True,\n            "n_jobs": 1,\n            "max_iter": max_iter,\n            "model_history": True,\n            "log_type": "all",\n            "starting_points": starting_points,\n            "append_log": True,\n        }\n        new_automl = AutoML()\n        new_automl.fit(X_train=X_train, y_train=y_train, **settings_resume)\n\n        new_automl_val_accuracy = 1.0 - new_automl.best_loss\n        # print(\'Best ML leaner:\', new_automl.best_estimator)\n        # print(\'Best hyperparmeter config:\', new_automl.best_config)\n        print(f"Best accuracy on validation data: {new_automl_val_accuracy:.4g}")\n        # print(\'Training duration of best run: {0:.4g} s\'.format(new_automl_experiment.best_config_train_time))\n\n\nif __name__ == "__main__":\n    unittest.main()\n',
            'website/docs/FAQ.md': '# Frequently Asked Questions\n\n### [Guidelines on how to set a hyperparameter search space](Use-Cases/Tune-User-Defined-Function#details-and-guidelines-on-hyperparameter-search-space)\n\n### [Guidelines on parallel vs seqential tuning](Use-Cases/Task-Oriented-AutoML#guidelines-on-parallel-vs-sequential-tuning)\n\n### [Guidelines on creating and tuning a custom estimator](Use-Cases/Task-Oriented-AutoML#guidelines-on-tuning-a-custom-estimator)\n\n### About `low_cost_partial_config` in `tune`.\n\n- Definition and purpose: The `low_cost_partial_config` is a dictionary of subset of the hyperparameter coordinates whose value corresponds to a configuration with known low-cost (i.e., low computation cost for training the corresponding model). The concept of low/high-cost is meaningful in the case where a subset of the hyperparameters to tune directly affects the computation cost for training the model. For example, `n_estimators` and `max_leaves` are known to affect the training cost of tree-based learners. We call this subset of hyperparameters, *cost-related hyperparameters*. In such scenarios, if you are aware of low-cost configurations for the cost-related hyperparameters, you are recommended to set them as the `low_cost_partial_config`. Using the tree-based method example again, since we know that small `n_estimators` and `max_leaves` generally correspond to simpler models and thus lower cost, we set `{\'n_estimators\': 4, \'max_leaves\': 4}` as the `low_cost_partial_config` by default (note that `4` is the lower bound of search space for these two hyperparameters), e.g., in [LGBM](https://github.com/microsoft/FLAML/blob/main/flaml/model.py#L215). Configuring `low_cost_partial_config` helps the search algorithms make more cost-efficient choices.\n  In AutoML, the `low_cost_init_value` in `search_space()` function for each estimator serves the same role.\n\n- Usage in practice: It is recommended to configure it if there are cost-related hyperparameters in your tuning task and you happen to know the low-cost values for them, but it is not required (It is fine to leave it the default value, i.e., `None`).\n\n- How does it work: `low_cost_partial_config` if configured, will be used as an initial point of the search. It also affects the search trajectory. For more details about how does it play a role in the search algorithms, please refer to the papers about the search algorithms used: Section 2 of [Frugal Optimization for Cost-related Hyperparameters (CFO)](https://arxiv.org/pdf/2005.01571.pdf) and Section 3 of [Economical Hyperparameter Optimization with Blended Search Strategy (BlendSearch)](https://openreview.net/pdf?id=VbLH04pRA3).\n\n### How does FLAML handle imbalanced data (unequal distribution of target classes in classification task)?\n\nCurrently FLAML does several things for imbalanced data.\n\n1. When a class contains fewer than 20 examples, we repeatedly add these examples to the training data until the count is at least 20.\n1. We use stratified sampling when doing holdout and kf.\n1. We make sure no class is empty in both training and holdout data.\n1. We allow users to pass `sample_weight` to `AutoML.fit()`.\n1. User can customize the weight of each class by setting the `custom_hp` or `fit_kwargs_by_estimator` arguments. For example, the following code sets the weight for pos vs. neg as 2:1 for the RandomForest estimator:\n\n```python\nfrom flaml import AutoML\nfrom sklearn.datasets import load_iris\n\nX_train, y_train = load_iris(return_X_y=True)\nautoml = AutoML()\nautoml_settings = {\n    "time_budget": 2,\n    "task": "classification",\n    "log_file_name": "test/iris.log",\n    "estimator_list": ["rf", "xgboost"],\n}\n\nautoml_settings["custom_hp"] = {\n    "xgboost": {\n        "scale_pos_weight": {\n            "domain": 0.5,\n            "init_value": 0.5,\n        }\n    },\n    "rf": {"class_weight": {"domain": "balanced", "init_value": "balanced"}},\n}\nprint(automl.model)\n```\n\n### How to interpret model performance? Is it possible for me to visualize feature importance, SHAP values, optimization history?\n\nYou can use `automl.model.estimator.feature_importances_` to get the `feature_importances_` for the best model found by automl. See an [example](Examples/AutoML-for-XGBoost#plot-feature-importance).\n\nPackages such as `azureml-interpret` and `sklearn.inspection.permutation_importance` can be used on `automl.model.estimator` to explain the selected model.\nModel explanation is frequently asked and adding a native support may be a good feature. Suggestions/contributions are welcome.\n\nOptimization history can be checked from the [log](Use-Cases/Task-Oriented-AutoML#log-the-trials). You can also [retrieve the log and plot the learning curve](Use-Cases/Task-Oriented-AutoML#plot-learning-curve).\n\n### How to resolve out-of-memory error in `AutoML.fit()`\n\n- Set `free_mem_ratio` a float between 0 and 1. For example, 0.2 means try to keep free memory above 20% of total memory. Training may be early stopped for memory consumption reason when this is set.\n- Set `model_history` False.\n- If your data are already preprocessed, set `skip_transform` False. If you can preprocess the data before the fit starts, this setting can save memory needed for preprocessing in `fit`.\n- If the OOM error only happens for some particular trials:\n  - set `use_ray` True. This will increase the overhead per trial but can keep the AutoML process running when a single trial fails due to OOM error.\n  - provide a more accurate [`size`](reference/automl/model#size) function for the memory bytes consumption of each config for the estimator causing this error.\n  - modify the [search space](Use-Cases/Task-Oriented-AutoML#a-shortcut-to-override-the-search-space) for the estimators causing this error.\n  - or remove this estimator from the `estimator_list`.\n- If the OOM error happens when ensembling, consider disabling ensemble, or use a cheaper ensemble option. ([Example](Use-Cases/Task-Oriented-AutoML#ensemble)).\n\n### How to get the best config of an estimator and use it to train the original model outside FLAML?\n\nWhen you finished training an AutoML estimator, you may want to use it in other code w/o depending on FLAML. You can get the `automl.best_config` and convert it to the parameters of the original model with below code:\n\n```python\nfrom flaml import AutoML\nfrom sklearn.datasets import load_iris\n\nX, y = load_iris(return_X_y=True)\nsettings = {"time_budget": 3}\nautoml = AutoML(**settings)\nautoml.fit(X, y)\n\nprint(f"{automl.best_estimator=}")\nprint(f"{automl.best_config=}")\nprint(f"params for best estimator: {automl.model.config2params(automl.best_config)}")\n```\n\nIf the automl instance is not accessible and you\'ve the `best_config`. You can also convert it with below code:\n\n```python\nfrom flaml.automl.task.factory import task_factory\n\ntask = "classification"\nbest_estimator = "rf"\nbest_config = {\n    "n_estimators": 15,\n    "max_features": 0.35807183923834934,\n    "max_leaves": 12,\n    "criterion": "gini",\n}\n\nmodel_class = task_factory(task).estimator_class_from_str(best_estimator)(task=task)\nbest_params = model_class.config2params(best_config)\n```\n\nThen you can use it to train the sklearn estimators directly:\n\n```python\nfrom sklearn.ensemble import RandomForestClassifier\n\nmodel = RandomForestClassifier(**best_params)\nmodel.fit(X, y)\n```\n\n### How to save and load an AutoML object? (`pickle` / `load_pickle`)\n\nFLAML provides `AutoML.pickle()` / `AutoML.load_pickle()` as a convenient and robust way to persist an AutoML run.\n\n```python\nfrom flaml import AutoML\n\nautoml = AutoML()\nautoml.fit(X_train, y_train, task="classification", time_budget=60)\n\n# Save\nautoml.pickle("automl.pkl")\n\n# Load\nautoml_loaded = AutoML.load_pickle("automl.pkl")\npred = automl_loaded.predict(X_test)\n```\n\nNotes:\n\n- If you used Spark estimators, `AutoML.pickle()` externalizes Spark ML models into an adjacent artifact folder and keeps\n  the pickle itself lightweight.\n- If you want to skip re-loading externalized Spark models (e.g., in an environment without Spark), use:\n\n```python\nautoml_loaded = AutoML.load_pickle("automl.pkl", load_spark_models=False)\n```\n\n### How to list all available estimators for a task?\n\nThe available estimator set is task-dependent and can vary with optional dependencies. You can list the estimator keys\nthat FLAML currently has registered in your environment:\n\n```python\nfrom flaml.automl.task.factory import task_factory\n\nprint(sorted(task_factory("classification").estimators.keys()))\nprint(sorted(task_factory("regression").estimators.keys()))\nprint(sorted(task_factory("forecast").estimators.keys()))\nprint(sorted(task_factory("rank").estimators.keys()))\n```\n\n### How to list supported built-in metrics?\n\n```python\nfrom flaml import AutoML\n\nautoml = AutoML()\nsklearn_metrics, hf_metrics, spark_metrics = automl.supported_metrics\nprint(sorted(sklearn_metrics))\nprint(sorted(hf_metrics))\nprint(spark_metrics)\n```\n',
            'website/docs/Use-Cases/Task-Oriented-AutoML.md': '# Task Oriented AutoML\n\n## Overview\n\n[`flaml.AutoML`](/docs/reference/automl/automl#automl-objects) is a class for task-oriented AutoML. It can be used as a scikit-learn style estimator with the standard `fit` and `predict` functions. The minimal inputs from users are the training data and the task type.\n\n- Training data:\n  - numpy array. When the input data are stored in numpy array, they are passed to `fit()` as `X_train` and `y_train`.\n  - pandas dataframe. When the input data are stored in pandas dataframe, they are passed to `fit()` either as `X_train` and `y_train`, or as `dataframe` and `label`.\n- Tasks (specified via `task`):\n  - \'classification\': classification with tabular data.\n  - \'regression\': regression with tabular data.\n  - \'ts_forecast\': time series forecasting.\n  - \'ts_forecast_classification\': time series forecasting for classification.\n  - \'ts_forecast_panel\': time series forecasting for panel datasets (multiple time series).\n  - \'rank\': learning to rank.\n  - \'seq-classification\': sequence classification.\n  - \'seq-regression\': sequence regression.\n  - \'summarization\': text summarization.\n  - \'token-classification\': token classification.\n  - \'multichoice-classification\': multichoice classification.\n\nTwo optional inputs are `time_budget` and `max_iter` for searching models and hyperparameters. When both are unspecified, only one model per estimator will be trained (using our [zero-shot](Zero-Shot-AutoML) technique). When `time_budget` is provided, there can be randomness in the result due to runtime variance.\n\nA typical way to use `flaml.AutoML`:\n\n```python\n# Prepare training data\n# ...\nfrom flaml import AutoML\n\nautoml = AutoML()\nautoml.fit(X_train, y_train, task="regression", time_budget=60, **other_settings)\n# Save the model\nautoml.pickle("automl.pkl")\n\n# At prediction time\nautoml = AutoML.load_pickle("automl.pkl")\npred = automl.predict(X_test)\n```\n\nFLAML also supports plain `pickle.dump()` / `pickle.load()`, but `automl.pickle()` / `AutoML.load_pickle()` is recommended,\nespecially when Spark estimators are involved.\n\nIf users provide the minimal inputs only, `AutoML` uses the default settings for optimization metric, estimator list etc.\n\n## Customize AutoML.fit()\n\n### Optimization metric\n\nThe optimization metric is specified via the `metric` argument. It can be either a string which refers to a built-in metric, or a user-defined function.\n\n- Built-in metric.\n  - \'accuracy\': 1 - accuracy as the corresponding metric to minimize.\n  - \'log_loss\': default metric for multiclass classification.\n  - \'r2\': 1 - r2_score as the corresponding metric to minimize. Default metric for regression.\n  - \'rmse\': root mean squared error.\n  - \'mse\': mean squared error.\n  - \'mae\': mean absolute error.\n  - \'mape\': mean absolute percentage error.\n  - \'roc_auc\': minimize 1 - roc_auc_score. Default metric for binary classification.\n  - \'roc_auc_ovr\': minimize 1 - roc_auc_score with `multi_class="ovr"`.\n  - \'roc_auc_ovo\': minimize 1 - roc_auc_score with `multi_class="ovo"`.\n  - \'roc_auc_weighted\': minimize 1 - roc_auc_score with `average="weighted"`.\n  - \'roc_auc_ovr_weighted\': minimize 1 - roc_auc_score with `multi_class="ovr"` and `average="weighted"`.\n  - \'roc_auc_ovo_weighted\': minimize 1 - roc_auc_score with `multi_class="ovo"` and `average="weighted"`.\n  - \'f1\': minimize 1 - f1_score.\n  - \'micro_f1\': minimize 1 - f1_score with `average="micro"`.\n  - \'macro_f1\': minimize 1 - f1_score with `average="macro"`.\n  - \'ap\': minimize 1 - average_precision_score.\n  - \'ndcg\': minimize 1 - ndcg_score.\n  - \'ndcg@k\': minimize 1 - ndcg_score@k. k is an integer.\n- User-defined function.\n  A customized metric function that requires the following (input) signature, and returns the input config’s value in terms of the metric you want to minimize, and a dictionary of auxiliary information at your choice:\n\n```python\ndef custom_metric(\n    X_val,\n    y_val,\n    estimator,\n    labels,\n    X_train,\n    y_train,\n    weight_val=None,\n    weight_train=None,\n    config=None,\n    groups_val=None,\n    groups_train=None,\n):\n    return metric_to_minimize, metrics_to_log\n```\n\nFor example,\n\n```python\ndef custom_metric(\n    X_val,\n    y_val,\n    estimator,\n    labels,\n    X_train,\n    y_train,\n    weight_val=None,\n    weight_train=None,\n    *args,\n):\n    from sklearn.metrics import log_loss\n    import time\n\n    start = time.time()\n    y_pred = estimator.predict_proba(X_val)\n    pred_time = (time.time() - start) / len(X_val)\n    val_loss = log_loss(y_val, y_pred, labels=labels, sample_weight=weight_val)\n    y_pred = estimator.predict_proba(X_train)\n    train_loss = log_loss(y_train, y_pred, labels=labels, sample_weight=weight_train)\n    alpha = 0.5\n    return val_loss * (1 + alpha) - alpha * train_loss, {\n        "val_loss": val_loss,\n        "train_loss": train_loss,\n        "pred_time": pred_time,\n    }\n```\n\nIt returns the validation loss penalized by the gap between validation and training loss as the metric to minimize, and three metrics to log: val_loss, train_loss and pred_time. The arguments `config`, `groups_val` and `groups_train` are not used in the function.\n\nYou can also inspect what FLAML recognizes as built-in metrics at runtime:\n\n```python\nfrom flaml import AutoML\n\nautoml = AutoML()\nsklearn_metrics, hf_metrics, spark_metrics = automl.supported_metrics\nprint(sorted(sklearn_metrics))\nprint(sorted(hf_metrics))\nprint(spark_metrics)\n```\n\n### Estimator and search space\n\nThe estimator list can contain one or more estimator names, each corresponding to a built-in estimator or a custom estimator. Each estimator has a search space for hyperparameter configurations. FLAML supports both classical machine learning models and deep neural networks.\n\n#### Estimator\n\n- Built-in estimator.\n  - \'lgbm\': LGBMEstimator for task "classification", "regression", "rank", "ts_forecast" and "ts_forecast_classification". Hyperparameters: n_estimators, num_leaves, min_child_samples, learning_rate, log_max_bin (logarithm of (max_bin + 1) with base 2), colsample_bytree, reg_alpha, reg_lambda.\n  - \'xgboost\': XGBoostSkLearnEstimator for task "classification", "regression", "rank", "ts_forecast" and "ts_forecast_classification". Hyperparameters: n_estimators, max_leaves, min_child_weight, learning_rate, subsample, colsample_bylevel, colsample_bytree, reg_alpha, reg_lambda.\n  - \'xgb_limitdepth\': XGBoostLimitDepthEstimator for task "classification", "regression", "rank", "ts_forecast" and "ts_forecast_classification". Hyperparameters: n_estimators, max_depth, min_child_weight, learning_rate, subsample, colsample_bylevel, colsample_bytree, reg_alpha, reg_lambda.\n  - \'rf\': RandomForestEstimator for task "classification", "regression", "ts_forecast" and "ts_forecast_classification". Hyperparameters: n_estimators, max_features, max_leaves, criterion (for classification only). Starting from v1.1.0,\n    it uses a fixed random_state by default.\n  - \'extra_tree\': ExtraTreesEstimator for task "classification", "regression", "ts_forecast" and "ts_forecast_classification". Hyperparameters: n_estimators, max_features, max_leaves, criterion (for classification only). Starting from v1.1.0,\n    it uses a fixed random_state by default.\n  - \'histgb\': HistGradientBoostingEstimator for task "classification", "regression", "ts_forecast" and "ts_forecast_classification". Hyperparameters: n_estimators, max_leaves, min_samples_leaf, learning_rate, log_max_bin (logarithm of (max_bin + 1) with base 2), l2_regularization. It uses a fixed random_state by default.\n  - \'lrl1\': LRL1Classifier (sklearn.LogisticRegression with L1 regularization) for task "classification". Hyperparameters: C.\n  - \'lrl2\': LRL2Classifier (sklearn.LogisticRegression with L2 regularization) for task "classification". Hyperparameters: C.\n  - \'catboost\': CatBoostEstimator for task "classification" and "regression". Hyperparameters: early_stopping_rounds, learning_rate, n_estimators.\n  - \'kneighbor\': KNeighborsEstimator for task "classification" and "regression". Hyperparameters: n_neighbors.\n  - \'prophet\': Prophet for task "ts_forecast". Hyperparameters: changepoint_prior_scale, seasonality_prior_scale, holidays_prior_scale, seasonality_mode.\n  - \'arima\': ARIMA for task "ts_forecast". Hyperparameters: p, d, q.\n  - \'sarimax\': SARIMAX for task "ts_forecast". Hyperparameters: p, d, q, P, D, Q, s.\n  - \'holt-winters\': Holt-Winters (triple exponential smoothing) model for task "ts_forecast". Hyperparameters: seasonal_perdiods, seasonal, use_boxcox, trend, damped_trend.\n  - \'transformer\': Huggingface transformer models for task "seq-classification", "seq-regression", "multichoice-classification", "token-classification" and "summarization". Hyperparameters: learning_rate, num_train_epochs, per_device_train_batch_size, warmup_ratio, weight_decay, adam_epsilon, seed.\n  - \'tft\': TemporalFusionTransformerEstimator for task "ts_forecast_panel". Hyperparameters: gradient_clip_val, hidden_size, hidden_continuous_size, attention_head_size, dropout, learning_rate.\n  - \'tcn\': Temporal Convolutional Network (TCN) estimator for task "ts_forecast" (requires optional deep learning dependencies, e.g., `torch` and `pytorch_lightning`).\n  - Spark estimators (for Spark / pandas-on-Spark DataFrames; the exact set depends on your Spark runtime and installed packages):\n    - \'lgbm_spark\': Spark LightGBM models via [SynapseML](https://microsoft.github.io/SynapseML/docs/features/lightgbm/about/).\n    - \'rf_spark\': Spark MLlib RandomForestClassifier/Regressor.\n    - \'gbt_spark\': Spark MLlib GBTClassifier/GBTRegressor.\n    - \'lr_spark\': Spark MLlib LinearRegression.\n    - \'glr_spark\': Spark MLlib GeneralizedLinearRegression.\n    - \'svc_spark\': Spark MLlib LinearSVC (binary classification only).\n    - \'nb_spark\': Spark MLlib NaiveBayes (classification only).\n    - \'aft_spark\': Spark MLlib AFTSurvivalRegression.\n- Custom estimator. Use custom estimator for:\n  - tuning an estimator that is not built-in;\n  - customizing search space for a built-in estimator.\n\n#### List all available estimators (recommended)\n\nThe exact set of available estimators depends on the `task` and optional dependencies (e.g., Prophet/Orbit/PyTorch).\nTo list the estimator keys available in your environment:\n\n```python\nfrom flaml.automl.task.factory import task_factory\n\nprint("classification:", sorted(task_factory("classification").estimators.keys()))\nprint("regression:", sorted(task_factory("regression").estimators.keys()))\nprint("forecast:", sorted(task_factory("forecast").estimators.keys()))\nprint("rank:", sorted(task_factory("rank").estimators.keys()))\n```\n\nFor reference, the built-in estimator keys included in the codebase are:\n\n- Tabular / ranking / NLP tasks (GenericTask):\n  `[\'aft_spark\', \'catboost\', \'enet\', \'extra_tree\', \'gbt_spark\', \'glr_spark\', \'histgb\', \'kneighbor\', \'lassolars\', \'lgbm\', \'lgbm_spark\', \'lr_spark\', \'lrl1\', \'lrl2\', \'nb_spark\', \'rf\', \'rf_spark\', \'sgd\', \'svc\', \'svc_spark\', \'transformer\', \'transformer_ms\', \'xgb_limitdepth\', \'xgboost\']`\n- Time series tasks (TimeSeriesTask):\n  `[\'arima\', \'avg\', \'catboost\', \'extra_tree\', \'holt-winters\', \'lassolars\', \'lgbm\', \'naive\', \'prophet\', \'rf\', \'sarimax\', \'savg\', \'snaive\', \'tcn\', \'tft\', \'xgb_limitdepth\', \'xgboost\', \'orbit\']`\n\nSome of the time series estimators (e.g., `prophet`, `orbit`, `tcn`, `tft`) are only available when the corresponding\noptional dependencies are installed.\n\n#### Guidelines on tuning a custom estimator\n\nTo tune a custom estimator that is not built-in, you need to:\n\n1. Build a custom estimator by inheritting [`flaml.automl.model.BaseEstimator`](/docs/reference/automl/model#baseestimator-objects) or a derived class.\n   For example, if you have a estimator class with scikit-learn style `fit()` and `predict()` functions, you only need to set `self.estimator_class` to be that class in your constructor.\n\n```python\nfrom flaml.automl.model import SKLearnEstimator\n# SKLearnEstimator is derived from BaseEstimator\nimport rgf\n\n\nclass MyRegularizedGreedyForest(SKLearnEstimator):\n    def __init__(self, task="binary", **config):\n        super().__init__(task, **config)\n\n        if task in CLASSIFICATION:\n        from rgf.sklearn import RGFClassifier\n\n        self.estimator_class = RGFClassifier\n        else:\n        from rgf.sklearn import RGFRegressor\n\n        self.estimator_class = RGFRegressor\n\n    @classmethod\n    def search_space(cls, data_size, task):\n        space = {\n        "max_leaf": {\n            "domain": tune.lograndint(lower=4, upper=data_size),\n            "low_cost_init_value": 4,\n        },\n        "n_iter": {\n            "domain": tune.lograndint(lower=1, upper=data_size),\n            "low_cost_init_value": 1,\n        },\n        "learning_rate": {"domain": tune.loguniform(lower=0.01, upper=20.0)},\n        "min_samples_leaf": {\n            "domain": tune.lograndint(lower=1, upper=20),\n            "init_value": 20,\n        },\n        }\n        return space\n```\n\nIn the constructor, we set `self.estimator_class` as `RGFClassifier` or `RGFRegressor` according to the task type. If the estimator you want to tune does not have a scikit-learn style `fit()` and `predict()` API, you can override the `fit()` and `predict()` function of `flaml.automl.model.BaseEstimator`, like [XGBoostEstimator](/docs/reference/automl/model#xgboostestimator-objects). Importantly, we also add the `task="binary"` parameter in the signature of `__init__` so that it doesn\'t get grouped together with the `**config` kwargs that determines the parameters with which the underlying estimator (`self.estimator_class`) is constructed. If your estimator doesn\'t use one of the parameters that it is passed, for example some regressors in `scikit-learn` don\'t use the `n_jobs` parameter, it is enough to add `n_jobs=None` to the signature so that it is ignored by the `**config` dict.\n\n2. Give the custom estimator a name and add it in AutoML. E.g.,\n\n```python\nfrom flaml import AutoML\n\nautoml = AutoML()\nautoml.add_learner("rgf", MyRegularizedGreedyForest)\n```\n\nThis registers the `MyRegularizedGreedyForest` class in AutoML, with the name "rgf".\n\n3. Tune the newly added custom estimator in either of the following two ways depending on your needs:\n\n- tune rgf alone: `automl.fit(..., estimator_list=["rgf"])`; or\n- mix it with other built-in learners: `automl.fit(..., estimator_list=["rgf", "lgbm", "xgboost", "rf"])`.\n\n#### Search space\n\nEach estimator class, built-in or not, must have a `search_space` function. In the `search_space` function, we return a dictionary about the hyperparameters, the keys of which are the names of the hyperparameters to tune, and each value is a set of detailed search configurations about the corresponding hyperparameters represented in a dictionary. A search configuration dictionary includes the following fields:\n\n- `domain`, which specifies the possible values of the hyperparameter and their distribution. Please refer to [more details about the search space domain](Tune-User-Defined-Function#more-details-about-the-search-space-domain).\n- `init_value` (optional), which specifies the initial value of the hyperparameter.\n- `low_cost_init_value`(optional), which specifies the value of the hyperparameter that is associated with low computation cost. See [cost related hyperparameters](Tune-User-Defined-Function#cost-related-hyperparameters) or [FAQ](/docs/FAQ#about-low_cost_partial_config-in-tune) for more details.\n\nIn the example above, we tune four hyperparameters, three integers and one float. They all follow a log-uniform distribution. "max_leaf" and "n_iter" have "low_cost_init_value" specified as their values heavily influence the training cost.\n\nTo customize the search space for a built-in estimator, use a similar approach to define a class that inherits the existing estimator. For example,\n\n```python\nfrom flaml.automl.model import XGBoostEstimator\n\n\ndef logregobj(preds, dtrain):\n    labels = dtrain.get_label()\n    preds = 1.0 / (1.0 + np.exp(-preds))  # transform raw leaf weight\n    grad = preds - labels\n    hess = preds * (1.0 - preds)\n    return grad, hess\n\n\nclass MyXGB1(XGBoostEstimator):\n    """XGBoostEstimator with logregobj as the objective function"""\n\n    def __init__(self, **config):\n        super().__init__(objective=logregobj, **config)\n```\n\nWe override the constructor and set the training objective as a custom function `logregobj`. The hyperparameters and their search range do not change. For another example,\n\n```python\nclass XGBoost2D(XGBoostSklearnEstimator):\n    @classmethod\n    def search_space(cls, data_size, task):\n        upper = min(32768, int(data_size))\n        return {\n            "n_estimators": {\n                "domain": tune.lograndint(lower=4, upper=upper),\n                "low_cost_init_value": 4,\n            },\n            "max_leaves": {\n                "domain": tune.lograndint(lower=4, upper=upper),\n                "low_cost_init_value": 4,\n            },\n        }\n```\n\nWe override the `search_space` function to tune two hyperparameters only, "n_estimators" and "max_leaves". They are both random integers in the log space, ranging from 4 to data-dependent upper bound. The lower bound for each corresponds to low training cost, hence the "low_cost_init_value" for each is set to 4.\n\n##### A shortcut to override the search space\n\nOne can use the `custom_hp` argument in [`AutoML.fit()`](/docs/reference/automl/automl#fit) to override the search space for an existing estimator quickly. For example, if you would like to temporarily change the search range of "n_estimators" of xgboost, disable searching "max_leaves" in random forest, and add "subsample" in the search space of lightgbm, you can set:\n\n```python\ncustom_hp = {\n    "xgboost": {\n        "n_estimators": {\n            "domain": tune.lograndint(lower=new_lower, upper=new_upper),\n            "low_cost_init_value": new_lower,\n        },\n    },\n    "rf": {\n        "max_leaves": {\n            "domain": None,  # disable search\n        },\n    },\n    "lgbm": {\n        "subsample": {\n            "domain": tune.uniform(lower=0.1, upper=1.0),\n            "init_value": 1.0,\n        },\n        "subsample_freq": {\n            "domain": 1,  # subsample_freq must > 0 to enable subsample\n        },\n    },\n}\n```\n\n### Constraint\n\nThere are several types of constraints you can impose.\n\n1. Constraints on the AutoML process.\n\n- `time_budget`: constrains the wall-clock time (seconds) used by the AutoML process. We provide some tips on [how to set time budget](#how-to-set-time-budget).\n\n- `max_iter`: constrains the maximal number of models to try in the AutoML process.\n\n2. Constraints on the constructor arguments of the estimators.\n\nSome constraints on the estimator can be implemented via the custom learner. For example,\n\n```python\nclass MonotonicXGBoostEstimator(XGBoostSklearnEstimator):\n    @classmethod\n    def search_space(**args):\n        space = super().search_space(**args)\n        space.update({"monotone_constraints": {"domain": "(1, -1)"}})\n        return space\n```\n\nIt adds a monotonicity constraint to XGBoost. This approach can be used to set any constraint that is an argument in the underlying estimator\'s constructor.\nA shortcut to do this is to use the [`custom_hp`](#a-shortcut-to-override-the-search-space) argument:\n\n```python\ncustom_hp = {\n    "xgboost": {\n        "monotone_constraints": {"domain": "(1, -1)"}  # fix the domain as a constant\n    }\n}\n```\n\n3. Constraints on the models tried in AutoML.\n\nUsers can set constraints such as the maximal number of models to try, limit on training time and prediction time per model.\n\n- `train_time_limit`: training time in seconds.\n- `pred_time_limit`: prediction time per instance in seconds.\n\nFor example,\n\n```python\nautoml.fit(X_train, y_train, max_iter=100, train_time_limit=1, pred_time_limit=1e-3)\n```\n\n4. Constraints on the metrics of the ML model tried in AutoML.\n\nWhen users provide a [custom metric function](#optimization-metric), which returns a primary optimization metric and a dictionary of additional metrics (typically also about the model) to log, users can also specify constraints on one or more of the metrics in the dictionary of additional metrics.\n\nUsers need to provide a list of such constraints in the following format:\nEach element in this list is a 3-tuple, which shall be expressed\nin the following format: the first element of the 3-tuple is the name of the\nmetric, the second element is the inequality sign chosen from ">=" and "\\<=",\nand the third element is the constraint value. E.g., `(\'val_loss\', \'<=\', 0.1)`.\n\nFor example,\n\n```python\nmetric_constraints = [("train_loss", "<=", 0.1), ("val_loss", "<=", 0.1)]\nautoml.fit(\n    X_train,\n    y_train,\n    max_iter=100,\n    train_time_limit=1,\n    metric_constraints=metric_constraints,\n)\n```\n\n### Ensemble\n\nTo use stacked ensemble after the model search, set `ensemble=True` or a dict. When `ensemble=True`, the final estimator and `passthrough` in the stacker will be automatically chosen. You can specify customized final estimator or passthrough option:\n\n- "final_estimator": an instance of the final estimator in the stacker.\n- "passthrough": True (default) or False, whether to pass the original features to the stacker.\n\nFor example,\n\n```python\nautoml.fit(\n    X_train, y_train, task="classification",\n    "ensemble": {\n        "final_estimator": LogisticRegression(),\n        "passthrough": False,\n    },\n)\n```\n\n### Resampling strategy\n\nBy default, flaml decides the resampling automatically according to the data size and the time budget. If you would like to enforce a certain resampling strategy, you can set `eval_method` to be "holdout" or "cv" for holdout or cross-validation.\n\nFor holdout, you can also set:\n\n- `split_ratio`: the fraction for validation data, 0.1 by default.\n- `X_val`, `y_val`: a separate validation dataset. When they are passed, the validation metrics will be computed against this given validation dataset. If they are not passed, then a validation dataset will be split from the training data and held out from training during the model search. After the model search, flaml will retrain the model with best configuration on the full training data.\n  You can set`retrain_full` to be `False` to skip the final retraining or "budget" to ask flaml to do its best to retrain within the time budget. When `retrain_full` is set to `True`, the user-provided validation data is not used in the final retraining of the model.\n\nFor cross validation, you can also set `n_splits` of the number of folds. By default it is 5.\n\n#### Data split method\n\nflaml relies on the provided task type to infer the default splitting strategy:\n\n- stratified split for classification;\n- uniform split for regression;\n- time-based split for time series forecasting;\n- group-based split for learning to rank.\n\nThe data split method for classification can be changed into uniform split by setting `split_type="uniform"`. The data are shuffled when `split_type in ("uniform", "stratified")`.\n\nFor both classification and regression tasks more advanced split configurations are possible:\n\n- time-based split can be enforced if the data are sorted by timestamps, by setting `split_type="time"`,\n- group-based splits can be set by using `split_type="group"` while providing the group identifier for each sample through the `groups` argument. This is also shown in an [example notebook](https://github.com/microsoft/FLAML/blob/main/notebook/basics/understanding_cross_validation.ipynb).\n\nMore in general, `split_type` can also be set as a custom splitter object, when `eval_method="cv"`. It needs to be an instance of a derived class of scikit-learn\n[KFold](https://scikit-learn.org/stable/modules/generated/sklearn.model_selection.KFold.html#sklearn.model_selection.KFold)\nand have `split` and `get_n_splits` methods with the same signatures. To disable shuffling, the splitter instance must contain the attribute `shuffle=False`.\n\n### Parallel tuning\n\nWhen you have parallel resources, you can either spend them in training and keep the model search sequential, or perform parallel search. Following scikit-learn, the parameter `n_jobs` specifies how many CPU cores to use for each training job. The number of parallel trials is specified via the parameter `n_concurrent_trials`. By default, `n_jobs=-1, n_concurrent_trials=1`. That is, all the CPU cores (in a single compute node) are used for training a single model and the search is sequential. When you have more resources than what each single training job needs, you can consider increasing `n_concurrent_trials`.\n\nFLAML now support two backends for parallel tuning, i.e., `Ray` and `Spark`. You can use either of them, but not both for one tuning job.\n\n#### Parallel tuning with Ray\n\nTo do parallel tuning with Ray, install the `ray` and `blendsearch` options:\n\n```bash\npip install flaml[ray,blendsearch]\n```\n\n`ray` is used to manage the resources. For example,\n\n```python\nray.init(num_cpus=16)\n```\n\nallocates 16 CPU cores. Then, when you run:\n\n```python\nautoml.fit(X_train, y_train, n_jobs=4, n_concurrent_trials=4)\n```\n\nflaml will perform 4 trials in parallel, each consuming 4 CPU cores. The parallel tuning uses the [BlendSearch](Tune-User-Defined-Function##blendsearch-economical-hyperparameter-optimization-with-blended-search-strategy) algorithm.\n\n#### Parallel tuning with Spark\n\nTo do parallel tuning with Spark, install the `spark` and `blendsearch` options:\n\n> *Spark support is added in v1.1.0*\n\n```bash\npip install flaml[spark,blendsearch]>=1.1.0\n```\n\nFor more details about installing Spark, please refer to [Installation](/docs/Installation#distributed-tuning).\n\nAn example of using Spark for parallel tuning is:\n\n```python\nautoml.fit(X_train, y_train, n_concurrent_trials=4, use_spark=True)\n```\n\nDetails about parallel tuning with Spark could be found [here](/docs/Examples/Integrate%20-%20Spark#parallel-spark-jobs). For Spark clusters, by default, we will launch one trial per executor. However, sometimes we want to launch more trials than the number of executors (e.g., local mode). In this case, we can set the environment variable `FLAML_MAX_CONCURRENT` to override the detected `num_executors`. The final number of concurrent trials will be the minimum of `n_concurrent_trials` and `num_executors`. Also, GPU training is not supported yet when use_spark is True.\n\n#### **Guidelines on parallel vs sequential tuning**\n\n**(1) Considerations on wall-clock time.**\n\nOne common motivation for parallel tuning is to save wall-clock time. When sequential tuning and parallel tuning achieve a similar wall-clock time, sequential tuning should be preferred. This is a rule of thumb when the HPO algorithm is sequential by nature (e.g., Bayesian Optimization and FLAML\'s HPO algorithms CFO and BS). Sequential tuning allows the HPO algorithms to take advantage of the historical trial results. Then the question is **How to estimate the wall-clock-time needed by parallel tuning and sequential tuning**?\n\nYou can use the following way to roughly estimate the wall-clock time in parallel tuning and sequential tuning: To finish $N$ trials of hyperparameter tuning, i.e., run $N$ hyperparameter configurations, the total wall-clock time needed is $N/k\\*(SingleTrialTime + Overhead)$, in which $SingleTrialTime$ is the trial time to evaluate a particular hyperparameter configuration, $k$ is the scale of parallelism, e.g., the number of parallel CPU/GPU cores, and $Overhead$ is the computation overhead.\n\nIn sequential tuning, $k=1$, and in parallel tuning $k>1$. This may suggest that parallel tuning has a shorter wall-clock time. But it is not always the case considering the other two factors $SingleTrialTime$, and $Overhead$:\n\n- The $Overhead$ in sequential tuning is typically negligible; while in parallel tuning, it is relatively large.\n\n- You can also try to reduce the $SingleTrialTime$ to reduce the wall-clock time in sequential tuning: For example, by increasing the resource consumed by a single trial (distributed or multi-thread training), you can reduce $SingleTrialTime$. One concrete example is to use the `n_jobs` parameter that sets the number of threads the fitting process can use in many scikit-learn style algorithms.\n\n**(2) Considerations on randomness.**\n\nPotential reasons that cause randomness:\n\n1. Parallel tuning: In the case of parallel tuning, the order of trials\' finishing time is no longer deterministic. This non-deterministic order, combined with sequential HPO algorithms, leads to a non-deterministic hyperparameter tuning trajectory.\n\n1. Distributed or multi-thread training: Distributed/multi-thread training may introduce randomness in model training, i.e., the trained model with the same hyperparameter may be different because of such randomness. This model-level randomness may be undesirable in some cases.\n\n### Warm start\n\nWe can warm start the AutoML by providing starting points of hyperparameter configurstions for each estimator. For example, if you have run AutoML for one hour, after checking the results, you would like to run it for another two hours, then you can use the best configurations found for each estimator as the starting points for the new run.\n\n```python\nautoml1 = AutoML()\nautoml1.fit(X_train, y_train, time_budget=3600)\nautoml2 = AutoML()\nautoml2.fit(\n    X_train,\n    y_train,\n    time_budget=7200,\n    starting_points=automl1.best_config_per_estimator,\n)\n```\n\n`starting_points` is a dictionary or a str to specify the starting hyperparameter config. (1) When it is a dictionary, the keys are the estimator names. If you do not need to specify starting points for an estimator, exclude its name from the dictionary. The value for each key can be either a dictionary of a list of dictionaries, corresponding to one hyperparameter configuration, or multiple hyperparameter configurations, respectively. (2) When it is a str: if "data", use data-dependent defaults; if "data:path", use data-dependent defaults which are stored at path; if "static", use data-independent defaults. Please find more details about data-dependent defaults in [zero shot AutoML](Zero-Shot-AutoML#combine-zero-shot-automl-and-hyperparameter-tuning).\n\n### Log the trials\n\nThe trials are logged in a file if a `log_file_name` is passed.\nEach trial is logged as a json record in one line. The best trial\'s id is logged in the last line. For example,\n\n```\n{"record_id": 0, "iter_per_learner": 1, "logged_metric": null, "trial_time": 0.12717914581298828, "wall_clock_time": 0.1728971004486084, "validation_loss": 0.07333333333333332, "config": {"n_estimators": 4, "num_leaves": 4, "min_child_samples": 20, "learning_rate": 0.09999999999999995, "log_max_bin": 8, "colsample_bytree": 1.0, "reg_alpha": 0.0009765625, "reg_lambda": 1.0}, "learner": "lgbm", "sample_size": 150}\n{"record_id": 1, "iter_per_learner": 3, "logged_metric": null, "trial_time": 0.07027268409729004, "wall_clock_time": 0.3756711483001709, "validation_loss": 0.05333333333333332, "config": {"n_estimators": 4, "num_leaves": 4, "min_child_samples": 12, "learning_rate": 0.2677050123105203, "log_max_bin": 7, "colsample_bytree": 1.0, "reg_alpha": 0.001348364934537134, "reg_lambda": 1.4442580148221913}, "learner": "lgbm", "sample_size": 150}\n{"curr_best_record_id": 1}\n```\n\n1. `iter_per_learner` means how many models have been tried for each learner. The reason you see records like `iter_per_learner=3` for `record_id=1` is that flaml only logs better configs than the previous iters by default, i.e., `log_type=\'better\'`. If you use `log_type=\'all\'` instead, all the trials will be logged.\n1. `trial_time` means the time taken to train and evaluate one config in that trial. `total_search_time` is the total time spent from the beginning of `fit()`.\n1. flaml will adjust the `n_estimators` for lightgbm etc. according to the remaining budget and check the time budget constraint and stop in several places. Most of the time that makes `fit()` stops before the given budget. Occasionally it may run over the time budget slightly. But the log file always contains the best config info and you can recover the best model until any time point using `retrain_from_log()`.\n\nWe can also use mlflow for logging:\n\n```python\nmlflow.set_experiment("flaml")\nwith mlflow.start_run():\n    automl.fit(X_train=X_train, y_train=y_train, **settings)\n```\n\nTo disable mlflow logging pre-configured in FLAML, set `mlflow_logging=False`:\n\n```python\nautoml = AutoML(mlflow_logging=False)\n```\n\nor\n\n```python\nautoml.fit(X_train=X_train, y_train=y_train, mlflow_logging=False, **settings)\n```\n\nSetting `mlflow_logging=False` in the constructor will disable mlflow logging for all the `fit()` calls.\nSetting `mlflow_logging=False` in `fit()` will disable mlflow logging for that `fit()` call only.\n\n### Extra fit arguments\n\nExtra fit arguments that are needed by the estimators can be passed to `AutoML.fit()`. For example, if there is a weight associated with each training example, they can be passed via `sample_weight`. For another example, `period` can be passed for time series forecaster. For any extra keywork argument passed to `AutoML.fit()` which has not been explicitly listed in the function signature, it will be passed to the underlying estimators\' `fit()` as is. For another example, you can set the number of gpus used by each trial with the `gpu_per_trial` argument, which is only used by TransformersEstimator and XGBoostSklearnEstimator.\n\nIn addition, you can specify the different arguments needed by different estimators using the `fit_kwargs_by_estimator` argument. For example, you can set the custom arguments for a Transformers model:\n\n```python\nfrom flaml.automl.data import load_openml_dataset\nfrom flaml import AutoML\n\nX_train, X_test, y_train, y_test = load_openml_dataset(dataset_id=1169, data_dir="./")\n\nautoml = AutoML()\nautoml_settings = {\n    "task": "classification",\n    "time_budget": 10,\n    "estimator_list": ["catboost", "rf"],\n    "fit_kwargs_by_estimator": {\n        "catboost": {\n            "verbose": True,  # setting the verbosity of catboost to True\n        }\n    },\n}\nautoml.fit(X_train=X_train, y_train=y_train, **automl_settings)\n```\n\n## Retrieve the Outcomes\n\n### Get best model\n\nThe best model can be obtained by the `model` property of an `AutoML` instance. For example,\n\n```python\nautoml.fit(X_train, y_train, task="regression")\nprint(automl.model)\n# <flaml.automl.model.LGBMEstimator object at 0x7f9b502c4550>\n```\n\n[`flaml.automl.model.LGBMEstimator`](/docs/reference/automl/model#lgbmestimator-objects) is a wrapper class for LightGBM models. To access the underlying model, use the `estimator` property of the `flaml.automl.model.LGBMEstimator` instance.\n\n```python\nprint(automl.model.estimator)\n"""\nLGBMRegressor(colsample_bytree=0.7610534336273627,\n              learning_rate=0.41929025492645006, max_bin=255,\n              min_child_samples=4, n_estimators=45, num_leaves=4,\n              reg_alpha=0.0009765625, reg_lambda=0.009280655005879943,\n              verbose=-1)\n"""\n```\n\nJust like a normal LightGBM model, we can inspect it. For example, we can plot the feature importance:\n\n```python\nimport matplotlib.pyplot as plt\n\nplt.barh(\n    automl.model.estimator.feature_name_, automl.model.estimator.feature_importances_\n)\n```\n\n![png](images/feature_importance.png)\n\n### Get best configuration\n\nWe can find the best estimator\'s name and best configuration by:\n\n```python\nprint(automl.best_estimator)\n# lgbm\nprint(automl.best_config)\n# {\'n_estimators\': 148, \'num_leaves\': 18, \'min_child_samples\': 3, \'learning_rate\': 0.17402065726724145, \'log_max_bin\': 8, \'colsample_bytree\': 0.6649148062238498, \'reg_alpha\': 0.0009765625, \'reg_lambda\': 0.0067613624509965}\n```\n\nWe can also find the best configuration per estimator.\n\n```python\nprint(automl.best_config_per_estimator)\n# {\'lgbm\': {\'n_estimators\': 148, \'num_leaves\': 18, \'min_child_samples\': 3, \'learning_rate\': 0.17402065726724145, \'log_max_bin\': 8, \'colsample_bytree\': 0.6649148062238498, \'reg_alpha\': 0.0009765625, \'reg_lambda\': 0.0067613624509965}, \'rf\': None, \'catboost\': None, \'xgboost\': {\'n_estimators\': 4, \'max_leaves\': 4, \'min_child_weight\': 1.8630223791106992, \'learning_rate\': 1.0, \'subsample\': 0.8513627344387318, \'colsample_bylevel\': 1.0, \'colsample_bytree\': 0.946138073111236, \'reg_alpha\': 0.0018311776973217073, \'reg_lambda\': 0.27901659190538414}, \'extra_tree\': {\'n_estimators\': 4, \'max_features\': 1.0, \'max_leaves\': 4}}\n```\n\nThe `None` value corresponds to the estimators which have not been tried.\n\nOther useful information:\n\n```python\nprint(automl.best_config_train_time)\n# 0.24841618537902832\nprint(automl.best_iteration)\n# 10\nprint(automl.best_loss)\n# 0.15448622217577546\nprint(automl.time_to_find_best_model)\n# 0.4167296886444092\nprint(automl.config_history)\n# {0: (\'lgbm\', {\'n_estimators\': 4, \'num_leaves\': 4, \'min_child_samples\': 20, \'learning_rate\': 0.09999999999999995, \'log_max_bin\': 8, \'colsample_bytree\': 1.0, \'reg_alpha\': 0.0009765625, \'reg_lambda\': 1.0}, 1.2300517559051514)}\n# Meaning: at iteration 0, the config tried is {\'n_estimators\': 4, \'num_leaves\': 4, \'min_child_samples\': 20, \'learning_rate\': 0.09999999999999995, \'log_max_bin\': 8, \'colsample_bytree\': 1.0, \'reg_alpha\': 0.0009765625, \'reg_lambda\': 1.0} for lgbm, and the wallclock time is 1.23s when this trial is finished.\n```\n\n### Plot learning curve\n\nTo plot how the loss is improved over time during the model search, first load the search history from the log file:\n\n```python\nfrom flaml.automl.data import get_output_from_log\n\ntime_history, best_valid_loss_history, valid_loss_history, config_history, metric_history =\n    get_output_from_log(filename=settings["log_file_name"], time_budget=120)\n```\n\nThen, assuming the optimization metric is "accuracy", we can plot the accuracy versus wallclock time:\n\n```python\nimport matplotlib.pyplot as plt\nimport numpy as np\n\nplt.title("Learning Curve")\nplt.xlabel("Wall Clock Time (s)")\nplt.ylabel("Validation Accuracy")\nplt.step(time_history, 1 - np.array(best_valid_loss_history), where="post")\nplt.show()\n```\n\n![png](images/curve.png)\n\nThe curve suggests that increasing the time budget may further improve the accuracy.\n\n### How to set time budget\n\n- If you have an exact constraint for the total search time, set it as the time budget.\n- If you have flexible time constraints, for example, your desirable time budget is t1=60s, and the longest time budget you can tolerate is t2=3600s, you can try the following two ways:\n\n1. set t1 as the time budget, and check the message in the console log in the end. If the budget is too small, you will see a warning like\n\n> WARNING - Time taken to find the best model is 91% of the provided time budget and not all estimators\' hyperparameter search converged. Consider increasing the time budget.\n\n2. set t2 as the time budget, and also set `early_stop=True`. If the early stopping is triggered, you will see a warning like\n\n> WARNING - All estimator hyperparameters local search has converged at least once, and the total search time exceeds 10 times the time taken to find the best model.\n\n> WARNING - Stopping search as early_stop is set to True.\n\n### How much time is needed to find the best model\n\nIf you want to get a sense of how much time is needed to find the best model, you can use `max_iter=2` to perform two trials first. The message will be like:\n\n> INFO - iteration 0, current learner lgbm\n\n> INFO - Estimated sufficient time budget=145194s. Estimated necessary time budget=2118s.\n\n> INFO - at 2.6s, estimator lgbm\'s best error=0.4459, best estimator lgbm\'s best error=0.4459\n\nYou will see that the time to finish the first and cheapest trial is 2.6 seconds. The estimated necessary time budget is 2118 seconds, and the estimated sufficient time budget is 145194 seconds. Note that this is only an estimated range to help you decide your budget.\n\nWhen the time budget is set too low, it can happen that no estimator is trained at all within the budget. In this case, it is recommanded to use `max_iter` instead of `time_budget`. This ensures that you have enough time to train a model without worring about variance of the execution time for the code before starting a trainning.\n',
        }
